      enabled: store?.mode_pickup_enabled ?? true,
    },
  ];


  return (
    <div className="bg-card rounded-xl p-4 sm:p-6 shadow-card space-y-4">
      <h3 className="font-semibold text-foreground flex items-center gap-2 text-sm sm:text-base">
        <Store className="h-4 w-4 sm:h-5 sm:w-5 text-primary" />
        Modos de Operação
      </h3>
      <p className="text-xs sm:text-sm text-muted-foreground">
        Selecione quais modalidades de atendimento estarão disponíveis para seus clientes.
      </p>

      <div className="space-y-3">
        {modes.map((mode) => (
          <div
            key={mode.id}
            className="flex items-center justify-between gap-3 p-3 rounded-lg bg-muted/50"
          >
            <div className="flex items-center gap-3 min-w-0">
              <div className={`h-10 w-10 rounded-xl flex items-center justify-center flex-shrink-0 ${mode.enabled ? 'bg-primary/20' : 'bg-muted'}`}>
                <mode.icon className={`h-5 w-5 ${mode.enabled ? 'text-primary' : 'text-muted-foreground'}`} />
              </div>
              <div className="min-w-0">
                <p className="font-medium text-foreground text-sm">{mode.label}</p>
                <p className="text-xs text-muted-foreground truncate">{mode.description}</p>
              </div>
            </div>
            <Switch
              checked={mode.enabled}
              onCheckedChange={(checked) => handleToggle(mode.id, checked)}
              disabled={updateStore.isPending}
            />
          </div>
        ))}

      </div>

      {/* Senha PDV */}
      <div className="border-t border-border pt-4 mt-4 space-y-3">
        <div className="flex items-center gap-2">
          <KeyRound className="h-4 w-4 text-primary" />
          <p className="font-medium text-foreground text-sm">Senha PDV</p>
        </div>
        <p className="text-xs text-muted-foreground">
          Defina uma senha para acesso ao PDV pela rota /pdv. Máximo de 8 caracteres.
        </p>
        <Input
          type="text"
          placeholder="Senha do PDV"
          value={pdvPassword}
          onChange={(e) => setPdvPassword(e.target.value.slice(0, 8))}
          maxLength={8}
          className="max-w-xs"
        />
        <p className="text-xs text-muted-foreground">{pdvPassword.length}/8 caracteres</p>
        <Button
          size="sm"
          disabled={updateStore.isPending}
          onClick={async () => {
            if (!store) return;
            try {
              await updateStore.mutateAsync({
                ...(store.id ? { id: store.id } : {}),
                pdv_password: pdvPassword || null,
              } as any);
              toast({ title: 'Senha PDV salva com sucesso!' });
            } catch {
              toast({ title: 'Erro ao salvar senha', variant: 'destructive' });
            }
          }}
        >
          {updateStore.isPending ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Save className="h-4 w-4 mr-2" />}
          Salvar Configurações
        </Button>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Loader2, Store, Phone, CreditCard, Truck, ChevronRight, Check, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { ImageUpload } from '@/components/admin/ImageUpload';
import { useUpdateStoreConfig, StoreConfig } from '@/hooks/useStore';
import { useToast } from '@/hooks/use-toast';

interface SetupWizardProps {
  store: StoreConfig;
  open: boolean;
  onComplete: () => void;
}

const steps = [
  { id: 'info', title: 'Informações', icon: Store },
  { id: 'contact', title: 'Contato', icon: Phone },
  { id: 'payment', title: 'Pagamento', icon: CreditCard },
  { id: 'delivery', title: 'Entrega', icon: Truck },
];

export function SetupWizard({ store, open, onComplete }: SetupWizardProps) {
  const { toast } = useToast();
  const updateStore = useUpdateStoreConfig();
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    name: '',
    logo_url: '',
    cover_url: '',
    address: '',
    phone_whatsapp: '',
    pix_key_type: 'Telefone',
    pix_key: '',
    delivery_fee: '5',
    delivery_time_min: '30',
    delivery_time_max: '45',
  });

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      handleComplete();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = async () => {
    if (!formData.name.trim()) {
      toast({
        title: 'Nome obrigatório',
        description: 'Por favor, informe o nome do seu restaurante',
        variant: 'destructive',
      });
      setCurrentStep(0);
      return;
    }

    try {
      await updateStore.mutateAsync({
        id: store.id,
        name: formData.name.trim(),
        logo_url: formData.logo_url || null,
        cover_url: formData.cover_url || null,
        address: formData.address || null,
        phone_whatsapp: formData.phone_whatsapp || null,
        pix_key_type: formData.pix_key_type,
        pix_key: formData.pix_key || null,
        delivery_fee: parseFloat(formData.delivery_fee.replace(',', '.')) || 5,
        delivery_time_min: parseInt(formData.delivery_time_min) || 30,
        delivery_time_max: parseInt(formData.delivery_time_max) || 45,
      });

      toast({
        title: '🎉 Configuração concluída!',
        description: 'Seu restaurante está pronto para receber pedidos.',
      });

      onComplete();
    } catch (error: any) {
      toast({
        title: 'Erro ao salvar',
        description: error.message,
        variant: 'destructive',
      });
    }
  };

  const renderStepContent = () => {
    switch (currentStep) {
      case 0:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">Nome do Restaurante *</label>
              <Input
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                placeholder="Ex: Pizzaria do João"
                className="mt-1"
                autoFocus
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Logo</label>
              <ImageUpload
                bucket="store-assets"
                currentUrl={formData.logo_url}
                onUpload={(url) => setFormData({ ...formData, logo_url: url })}
                onRemove={() => setFormData({ ...formData, logo_url: '' })}
                className="mt-1"
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Imagem de Capa</label>
              <ImageUpload
                bucket="store-assets"
                currentUrl={formData.cover_url}
                onUpload={(url) => setFormData({ ...formData, cover_url: url })}
                onRemove={() => setFormData({ ...formData, cover_url: '' })}
                className="mt-1"
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Endereço</label>
              <Input
                value={formData.address}
                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                placeholder="Rua, número, bairro, cidade"
                className="mt-1"
              />
            </div>
          </div>
        );

      case 1:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">WhatsApp</label>
              <Input
                value={formData.phone_whatsapp}
                onChange={(e) => setFormData({ ...formData, phone_whatsapp: e.target.value })}
                placeholder="11999999999"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">
                Apenas números, com DDD. Os clientes usarão para contato.
              </p>
            </div>
          </div>
        );

      case 2:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">Tipo da Chave PIX</label>
              <Select
                value={formData.pix_key_type}
                onValueChange={(value) => setFormData({ ...formData, pix_key_type: value })}
              >
                <SelectTrigger className="mt-1">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Telefone">Telefone</SelectItem>
                  <SelectItem value="CPF">CPF</SelectItem>
                  <SelectItem value="CNPJ">CNPJ</SelectItem>
                  <SelectItem value="Email">Email</SelectItem>
                  <SelectItem value="Aleatória">Aleatória</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Chave PIX</label>
              <Input
                value={formData.pix_key}
                onChange={(e) => setFormData({ ...formData, pix_key: e.target.value })}
                placeholder="Sua chave PIX"
                className="mt-1"
              />
            </div>
          </div>
        );

      case 3:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">Taxa de Entrega (R$)</label>
              <Input
                value={formData.delivery_fee}
                onChange={(e) => setFormData({ ...formData, delivery_fee: e.target.value })}
                placeholder="5,00"
                className="mt-1"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium text-foreground">Tempo Mínimo (min)</label>
                <Input
                  value={formData.delivery_time_min}
                  onChange={(e) => setFormData({ ...formData, delivery_time_min: e.target.value })}
                  placeholder="30"
                  className="mt-1"
                  type="number"
                />
              </div>
              <div>
                <label className="text-sm font-medium text-foreground">Tempo Máximo (min)</label>
                <Input
                  value={formData.delivery_time_max}
                  onChange={(e) => setFormData({ ...formData, delivery_time_max: e.target.value })}
                  placeholder="45"
                  className="mt-1"
                  type="number"
                />
              </div>
            </div>
            <p className="text-xs text-muted-foreground">
              Tempo estimado de entrega que aparecerá para os clientes.
            </p>
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <Dialog open={open}>
      <DialogContent className="sm:max-w-lg" hideCloseButton>
        <DialogHeader>
          <div className="flex items-center gap-2 mb-2">
            <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center">
              <Sparkles className="h-5 w-5 text-primary" />
            </div>
            <div>
              <DialogTitle>Configure seu Restaurante</DialogTitle>
              <DialogDescription>
                Vamos configurar as informações básicas do seu negócio
              </DialogDescription>
            </div>
          </div>
        </DialogHeader>

        {/* Steps indicator */}
        <div className="flex justify-between mb-6">
          {steps.map((step, index) => {
            const Icon = step.icon;
            const isActive = index === currentStep;
            const isCompleted = index < currentStep;

            return (
              <div
                key={step.id}
                className={`flex flex-col items-center gap-1 ${
                  isActive ? 'text-primary' : isCompleted ? 'text-secondary' : 'text-muted-foreground'
                }`}
              >
                <div
                  className={`h-10 w-10 rounded-full flex items-center justify-center transition-colors ${
                    isActive
                      ? 'bg-primary text-primary-foreground'
                      : isCompleted
                      ? 'bg-secondary text-secondary-foreground'
                      : 'bg-muted'
                  }`}
                >
                  {isCompleted ? <Check className="h-5 w-5" /> : <Icon className="h-5 w-5" />}
                </div>
                <span className="text-xs font-medium">{step.title}</span>
              </div>
            );
          })}
        </div>

        {/* Step content */}
        <div className="min-h-[240px]">{renderStepContent()}</div>

        {/* Navigation */}
        <div className="flex justify-between pt-4">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 0}
          >
            Voltar
          </Button>
          <Button onClick={handleNext} disabled={updateStore.isPending}>
            {updateStore.isPending ? (
              <>
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
                Salvando...
              </>
            ) : currentStep === steps.length - 1 ? (
              <>
                Concluir
                <Check className="h-4 w-4 ml-2" />
              </>
            ) : (
              <>
                Próximo
                <ChevronRight className="h-4 w-4 ml-2" />
              </>
            )}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { useStore, useUpdateStore } from '@/hooks/useStore';
import { useToast } from '@/hooks/use-toast';
import { Globe, Copy, Check, ExternalLink, Info, Loader2, Server, FolderUp, FileCode } from 'lucide-react';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';

export function SubdomainSettings() {
  const { data: storeConfig } = useStore();
  const updateConfig = useUpdateStore();
  const { toast } = useToast();

  const [subdomain, setSubdomain] = useState('');
  const [copied, setCopied] = useState<string | null>(null);

  useEffect(() => {
    if (storeConfig?.subdomain_slug) {
      setSubdomain(storeConfig.subdomain_slug);
    }
  }, [storeConfig?.subdomain_slug]);

  const handleSubdomainChange = (value: string) => {
    const cleanValue = value.toLowerCase().replace(/[^a-z0-9-]/g, '');
    setSubdomain(cleanValue);
  };

  const handleSave = async () => {
    try {
      const updateData: any = {
        subdomain_slug: subdomain || null,
      };

      if (storeConfig?.id) {
        updateData.id = storeConfig.id;
      }

      await updateConfig.mutateAsync(updateData);
      toast({ title: 'Subdomínio salvo com sucesso!' });
    } catch (error) {
      toast({ 
        title: 'Erro ao salvar', 
        description: 'Não foi possível salvar o subdomínio.',
        variant: 'destructive' 
      });
    }
  };

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    setCopied(label);
    setTimeout(() => setCopied(null), 2000);
    toast({ title: 'Copiado!' });
  };

  const fullDomain = subdomain ? `${subdomain}.infornexa.com.br` : '';
  const supabaseUrl = import.meta.env.VITE_API_URL || '';

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center gap-2">
          <Globe className="h-5 w-5 text-primary" />
          <CardTitle className="text-lg">URL do Cardápio</CardTitle>
        </div>
        <CardDescription>
          Configure o subdomínio e veja como hospedar seu cardápio na Hostgator
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {/* Subdomain Input */}
        <div className="space-y-2">
          <label className="text-sm font-medium">Subdomínio</label>
          <div className="flex items-center gap-2">
            <div className="flex-1 flex items-center">
              <Input
                value={subdomain}
                onChange={(e) => handleSubdomainChange(e.target.value)}
                placeholder="meucardapio"
                className="rounded-r-none"
              />
              <span className="bg-muted px-3 py-2 border border-l-0 rounded-r-md text-sm text-muted-foreground whitespace-nowrap">
                .infornexa.com.br
              </span>
            </div>
            <Button onClick={handleSave} disabled={updateConfig.isPending}>
              {updateConfig.isPending ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  Salvando...
                </>
              ) : 'Salvar'}
            </Button>
          </div>
          <p className="text-xs text-muted-foreground">
            Use apenas letras minúsculas, números e hífens.
          </p>
        </div>

        {/* Preview URL */}
        {subdomain && (
          <div className="p-4 bg-primary/5 border border-primary/20 rounded-lg space-y-3">
            <div className="flex items-center gap-2">
              <Badge className="bg-primary text-primary-foreground">
                <ExternalLink className="h-3 w-3 mr-1" />
                URL Final do Cardápio
              </Badge>
            </div>
            <div className="flex items-center gap-2">
              <code className="flex-1 bg-background px-3 py-2 rounded text-sm border font-semibold">
                https://{fullDomain}
              </code>
              <Button
                variant="outline"
                size="icon"
                onClick={() => copyToClipboard(`https://${fullDomain}`, 'url')}
              >
                {copied === 'url' ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
              </Button>
            </div>
          </div>
        )}

        {/* Deployment Instructions */}
        {subdomain && (
          <Accordion type="single" collapsible className="w-full">
            {/* Step 1: Create Subdomain */}
            <AccordionItem value="step-1">
              <AccordionTrigger className="hover:no-underline">
                <div className="flex items-center gap-3">
                  <div className="flex items-center justify-center w-6 h-6 rounded-full bg-primary text-primary-foreground text-xs font-bold">
                    1
                  </div>
                  <span>Criar subdomínio na Hostgator</span>
                </div>
              </AccordionTrigger>
              <AccordionContent className="pl-9 space-y-3">
                <ol className="list-decimal list-inside space-y-2 text-sm text-muted-foreground">
                  <li>Acesse o <strong>cPanel</strong> da sua conta Hostgator</li>
                  <li>Vá em <strong>Domínios → Subdomínios</strong></li>
                  <li>No campo "Subdomínio", digite: <code className="bg-muted px-1.5 py-0.5 rounded font-mono">{subdomain}</code></li>
                  <li>No campo "Domínio", selecione: <code className="bg-muted px-1.5 py-0.5 rounded font-mono">infornexa.com.br</code></li>
                  <li>O campo "Raiz do documento" será preenchido automaticamente</li>
                  <li>Clique em <strong>Criar</strong></li>
                </ol>
              </AccordionContent>
            </AccordionItem>

            {/* Step 2: Upload Files */}
            <AccordionItem value="step-2">
              <AccordionTrigger className="hover:no-underline">
                <div className="flex items-center gap-3">
                  <div className="flex items-center justify-center w-6 h-6 rounded-full bg-primary text-primary-foreground text-xs font-bold">
                    2
                  </div>
                  <span>Fazer upload dos arquivos</span>
                </div>
              </AccordionTrigger>
              <AccordionContent className="pl-9 space-y-3">
                <ol className="list-decimal list-inside space-y-2 text-sm text-muted-foreground">
                  <li>No cPanel, vá em <strong>Arquivos → Gerenciador de Arquivos</strong></li>
