import { Trash2, Lock, ArrowRight, Loader2, FileDown, Printer, UtensilsCrossed } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { useComandaOrderDetails, Comanda } from '@/hooks/useComandas';
import { useMemo } from 'react';
import { useStoreConfig } from '@/hooks/useStore';
import { PrintOrderData, generateOrderPDF, generateThermalPDF } from '@/utils/thermalPrinter';
import { toast } from 'sonner';

const formatCurrency = (v: number) => {
  const safe = Number.isFinite(v) ? v : 0;
  return safe.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
};

interface CloseComandaCardProps {
  comanda: Comanda;
  onClose: () => void;
  onTransfer: () => void;
  onDelete?: () => void;
  deleteIsPending?: boolean;
}

export function CloseComandaCard({ comanda, onClose, onTransfer, onDelete, deleteIsPending }: CloseComandaCardProps) {
  const { data: comandaOrdersData, isLoading } = useComandaOrderDetails(comanda.id);
  const { data: store } = useStoreConfig();

  const total = useMemo(() => {
    let sum = 0;
    (comandaOrdersData || []).forEach((order: any) => {
      (order.items || []).forEach((item: any) => {
        sum += (Number(item.unit_price) || 0) * (item.quantity || 0);
      });
    });
    return sum;
  }, [comandaOrdersData]);

  const getPrintData = (): PrintOrderData | null => {
    const allItems: any[] = [];

    if (!comandaOrdersData?.length) return null;
    comandaOrdersData.forEach((order: any) => {
      (order.items || []).forEach((item: any) => {
        const existing = allItems.find(i => i.name === item.product_name && i.unitPrice === Number(item.unit_price) && i.observation === item.observation);
        if (existing) {
          existing.quantity += item.quantity;
        } else {
          allItems.push({
            name: item.product_name,
            quantity: item.quantity,
            unitPrice: Number(item.unit_price),
            observation: item.observation || undefined,
          });
        }
      });
    });

    return {
      orderNumber: comanda.numero_comanda,
      orderType: 'table',
      tableName: `Comanda #${comanda.numero_comanda}`,
      storeName: store?.name || 'Estabelecimento',
      items: allItems,
      subtotal: total,
      total: total,
      createdAt: new Date(),
    };
  };

  const handlePrintPDF = (e: React.MouseEvent) => {
    e.stopPropagation();
    const data = getPrintData();
    if (!data) return;
    try {
      generateOrderPDF(data);
      toast.success('PDF exportado com sucesso!');
    } catch (error) {
      toast.error('Erro ao exportar PDF');
    }
  };

  const handlePrintThermal = (e: React.MouseEvent) => {
    e.stopPropagation();
    const data = getPrintData();
    if (!data) return;
    try {
      generateThermalPDF(data);
    } catch (error) {
      toast.error('Erro ao gerar impressão térmica');
    }
  };

  return (
    <Card
      className="admin-card border-none shadow-lg relative cursor-pointer hover:ring-4 hover:ring-primary/20 transition-all active:scale-[0.98] group overflow-hidden"
      onClick={onClose}
    >
      <CardContent className="p-8 text-center">
        {onDelete && (
          <Button
            variant="ghost"
            size="icon-sm"
            className="absolute top-1 right-1 h-7 w-7 text-muted-foreground hover:text-destructive hover:bg-destructive/10 z-10"
            onClick={(e) => { e.stopPropagation(); onDelete(); }}
            title="Excluir comanda"
            disabled={deleteIsPending}
          >
            {deleteIsPending ? <Loader2 className="h-3 w-3 animate-spin" /> : <Trash2 className="h-3 w-3" />}
          </Button>
        )}

        <Lock className="h-8 w-8 mx-auto mb-2 text-destructive" />
        <p className="font-bold text-lg">Comanda #{comanda.numero_comanda}</p>
        <Badge variant="destructive" className="mt-1">
          Ocupada
        </Badge>

        <div className="mt-4 pt-4 border-t border-border space-y-4">
          {isLoading ? (
            <Loader2 className="h-4 w-4 animate-spin mx-auto text-muted-foreground" />
          ) : (
            <p className="font-bold text-primary text-xl">{formatCurrency(total)}</p>
          )}

          <div className="grid grid-cols-2 gap-2">
            <Button 
              variant="outline" 
              size="sm" 
              className="text-[10px] h-8 px-2"
              onClick={handlePrintPDF}
              disabled={isLoading || !comandaOrdersData?.length}
            >
              <FileDown className="h-3 w-3 mr-1" />
              PDF
            </Button>
            <Button 
              variant="outline" 
              size="sm" 
              className="text-[10px] h-8 px-2"
              onClick={handlePrintThermal}
              disabled={isLoading || !comandaOrdersData?.length}
            >
              <Printer className="h-3 w-3 mr-1" />
              Térmica
            </Button>
          </div>

          <Button 
            variant="outline" 
            size="sm" 
            className="w-full text-xs h-8"
            onClick={(e) => {
              e.stopPropagation();
              onTransfer();
            }}
          >
            <ArrowRight className="h-3 w-3 mr-2" />
            Transferir Pedidos
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState, useMemo } from 'react';
import { X, CreditCard, Banknote, Smartphone, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { useComandaOrderDetails, useCloseSale, Comanda } from '@/hooks/useComandas';
import { useToast } from '@/hooks/use-toast';
import { useOpenedSession, useAddMovimentacao } from '@/hooks/useCaixa';

interface CloseSaleModalProps {
  comanda: Comanda;
  open: boolean;
  onClose: () => void;
}

type PaymentMethod = 'money' | 'pix' | 'debit' | 'credit';

const paymentOptions: { value: PaymentMethod; label: string; icon: React.ReactNode }[] = [
  { value: 'money', label: 'Dinheiro', icon: <Banknote className="h-5 w-5" /> },
  { value: 'pix', label: 'Pix', icon: <Smartphone className="h-5 w-5" /> },
  { value: 'debit', label: 'Débito', icon: <CreditCard className="h-5 w-5" /> },
  { value: 'credit', label: 'Crédito', icon: <CreditCard className="h-5 w-5" /> },
];

const formatCurrency = (v: number) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

export function CloseSaleModal({ comanda, open, onClose }: CloseSaleModalProps) {
  const { toast } = useToast();

  const { data: comandaOrdersData, isLoading } = useComandaOrderDetails(comanda?.id);

  const closeSale = useCloseSale();

  const { data: activeSession } = useOpenedSession();
  const addMovimentacao = useAddMovimentacao();

  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod | null>(null);
  const [valorRecebido, setValorRecebido] = useState('');

  // Flatten all items
  const allItems = useMemo(() => {
    const itemMap = new Map<string, { product_name: string; quantity: number; unit_price: number; observation?: string }>();

    if (!comandaOrdersData) return [];
    comandaOrdersData.forEach(order => {
      if (!order) return;
      (order.items || []).forEach((item: any) => {
        const name = (item.product_name || '').trim();
        const price = Number(item.unit_price) || 0;
        const observation = (item.observation || '').trim();
        const key = `${name}-${price}-${observation}`;
        const existing = itemMap.get(key);
        if (existing) {
          existing.quantity += item.quantity;
        } else {
          itemMap.set(key, {
            product_name: name,
            quantity: item.quantity,
            unit_price: price,
            observation: observation,
          });
        }
      });
    });

    return Array.from(itemMap.values());
  }, [comandaOrdersData]);

  const total = allItems.reduce((sum, item) => sum + item.unit_price * item.quantity, 0);
  const valorRecebidoNum = parseFloat(valorRecebido) || 0;
  const troco = selectedPayment === 'money' ? Math.max(0, valorRecebidoNum - total) : 0;

  const canConfirm = selectedPayment && (selectedPayment !== 'money' || valorRecebidoNum >= total);

  const handleConfirm = async () => {
    if (!selectedPayment) return;

    try {
      await closeSale.mutateAsync({
        comandaId: comanda.id,
        valorTotal: total,
        formaPagamento: selectedPayment,
      });

      // Se for dinheiro e tiver um caixa aberto, registra a entrada
      if (selectedPayment === 'money' && activeSession) {
        await addMovimentacao.mutateAsync({
          sessionId: activeSession.id,
          type: 'entrada',
          amount: total,
          description: `Venda Comanda #${comanda.numero_comanda}`,
        });
      }

      toast({ 
        title: 'Venda fechada!', 
        description: `Comanda #${comanda.numero_comanda} finalizada com sucesso.` 
      });
      onClose();
    } catch (err: any) {
      toast({ title: 'Erro ao fechar venda', description: err.message, variant: 'destructive' });
    }
  };

  const title = `Comanda #${comanda?.numero_comanda}`;

  return (
    <Dialog open={open} onOpenChange={v => !v && onClose()}>
      <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Fechar Venda - {title}</DialogTitle>
        </DialogHeader>

        {isLoading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin" />
          </div>
        ) : allItems.length === 0 ? (
          <p className="text-center text-muted-foreground py-8">Nenhum item nesta comanda.</p>
        ) : (
          <div className="space-y-4">
            {/* Items list */}
            <div className="space-y-2">
              <h3 className="font-semibold text-sm text-muted-foreground uppercase">Itens</h3>
              {allItems.map((item, i) => (
                <div key={i} className="flex items-center justify-between text-sm py-1.5 border-b border-border last:border-0">
                  <div className="flex-1">
                    <div className="flex items-center">
                      <span className="font-medium text-foreground">{item.product_name}</span>
                      <span className="text-muted-foreground ml-2">x{item.quantity}</span>
                    </div>
                    {item.observation && (
                      <p className="text-xs text-muted-foreground italic leading-tight mt-0.5">{item.observation}</p>
                    )}
                  </div>
                  <span className="font-medium">{formatCurrency(item.unit_price * item.quantity)}</span>
                </div>
              ))}
            </div>

            {/* Total */}
            <div className="bg-muted/50 rounded-lg p-4">
              <div className="flex justify-between items-center text-lg font-bold">
                <span>Total</span>
                <span className="text-primary">{formatCurrency(total)}</span>
              </div>
            </div>

            {/* Payment selection */}
            <div className="space-y-2">
              <h3 className="font-semibold text-sm text-muted-foreground uppercase">Forma de Pagamento</h3>
              <div className="grid grid-cols-2 gap-2">
                {paymentOptions.map(opt => (
                  <Card
                    key={opt.value}
                    className={`cursor-pointer transition-all ${
                      selectedPayment === opt.value
                        ? 'ring-2 ring-primary bg-primary/5'
                        : 'hover:ring-1 hover:ring-primary/30'
                    }`}
                    onClick={() => {
                      setSelectedPayment(opt.value);
                      if (opt.value !== 'money') setValorRecebido('');
                    }}
                  >
                    <CardContent className="p-3 flex items-center gap-2 justify-center">
                      {opt.icon}
                      <span className="font-medium text-sm">{opt.label}</span>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </div>

            {/* Cash change calculation */}
            {selectedPayment === 'money' && (
              <div className="space-y-2">
                <label className="text-sm font-medium">Valor Recebido</label>
                <Input
                  type="number"
                  placeholder="0,00"
                  value={valorRecebido}
                  onChange={e => setValorRecebido(e.target.value)}
                  min={0}
                  step="0.01"
                />
                {valorRecebidoNum > 0 && valorRecebidoNum >= total && (
                  <div className="bg-accent/20 rounded-lg p-3 flex justify-between items-center">
                    <span className="font-medium">Troco</span>
                    <span className="font-bold text-lg text-primary">{formatCurrency(troco)}</span>
                  </div>
                )}
                {valorRecebidoNum > 0 && valorRecebidoNum < total && (
                  <p className="text-sm text-destructive">Valor insuficiente</p>
                )}
              </div>
            )}

            {/* Confirm button */}
            <Button
              className="w-full"
              size="lg"
              disabled={!canConfirm || closeSale.isPending}
              onClick={handleConfirm}
            >
              {closeSale.isPending ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : null}
              Confirmar Pagamento
            </Button>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { ChevronDown, ChevronUp, Plus, Trash2, Loader2, ShoppingBag } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { useComandaOrderDetails, Comanda } from '@/hooks/useComandas';
import { useMemo } from 'react';

const formatCurrency = (v: number) => {
  const safe = Number.isFinite(v) ? v : 0;
  return safe.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
};


interface ComandaConsumoCardProps {
  comanda: Comanda;
  onAddMore: (comanda: Comanda) => void;
}

export function ComandaConsumoCard({ comanda, onAddMore }: ComandaConsumoCardProps) {
  const [expanded, setExpanded] = useState(false);

  // Fetch for comandas
  const { data: comandaOrdersData, isLoading } = useComandaOrderDetails(comanda.id);

  const allItems = useMemo(() => {
    const itemMap = new Map<string, { product_name: string; quantity: number; unit_price: number; observation?: string }>();

    // Comanda orders are grouped
    const orders = Array.isArray(comandaOrdersData) ? comandaOrdersData : [];
    orders.forEach(order => {
      (order.items || []).forEach((item: any) => {
        const name = (item.product_name || '').trim();
        const price = Number(item.unit_price) || 0;
        const observation = (item.observation || '').trim();
        const key = `${name}-${price}-${observation}`;
        const existing = itemMap.get(key);
        if (existing) {
          existing.quantity += item.quantity;
        } else {
          itemMap.set(key, {
            product_name: name,
            quantity: item.quantity,
            unit_price: price,
            observation: observation,
          });
        }
      });
    });
    return Array.from(itemMap.values());
  }, [comandaOrdersData]);

  const total = allItems.reduce((sum, item) => sum + item.unit_price * item.quantity, 0);

  return (
    <Card className="admin-card border-none shadow-lg overflow-hidden transition-all duration-300">
      <CardContent className="p-0">
        <button
          className="w-full flex items-center justify-between p-4 hover:bg-muted/30 transition-colors text-left"
          onClick={() => setExpanded(!expanded)}
        >
          <div className="flex items-center gap-3">
            <ShoppingBag className="h-5 w-5 text-primary" />
          <span className="font-bold text-foreground">
            Comanda #{comanda.numero_comanda}
          </span>
          <Badge variant="destructive" className="text-xs">Ocupada</Badge>
          </div>
          <div className="flex items-center gap-3">
            {!isLoading && allItems.length > 0 && (
              <span className="text-sm font-semibold text-primary">{formatCurrency(total)}</span>
            )}
            {expanded ? <ChevronUp className="h-4 w-4 text-muted-foreground" /> : <ChevronDown className="h-4 w-4 text-muted-foreground" />}
          </div>
        </button>

        {expanded && (
          <div className="border-t border-border px-4 pb-4 space-y-3">
            {isLoading ? (
              <div className="flex justify-center py-4">
                <Loader2 className="h-5 w-5 animate-spin text-primary" />
              </div>
            ) : allItems.length === 0 ? (
              <p className="text-sm text-muted-foreground text-center py-4">Nenhum item nesta comanda.</p>
            ) : (
              <div className="space-y-2 pt-3">
                {allItems.map((item, i) => (
                  <div key={i} className="flex items-center justify-between text-sm py-1.5 border-b border-border last:border-0">
                    <div className="flex-1">
                      <div className="flex items-center">
                        <span className="font-medium text-foreground">{item.product_name}</span>
                        <span className="text-muted-foreground ml-2">x{item.quantity}</span>
                      </div>
                      {item.observation && (
                        <p className="text-[11px] text-muted-foreground italic leading-tight mt-0.5">{item.observation}</p>
                      )}
                    </div>
                    <span className="font-semibold text-primary">{formatCurrency(item.unit_price * item.quantity)}</span>
                  </div>
                ))}
                <div className="bg-muted/50 rounded-lg p-3 flex justify-between items-center mt-2">
                  <span className="font-bold text-foreground">Total</span>
                  <span className="font-bold text-lg text-primary">{formatCurrency(total)}</span>
                </div>
              </div>
            )}

            <div className="flex gap-2 pt-2">
              <Button variant="outline" className="w-full" onClick={() => onAddMore(comanda)}>
                <Plus className="h-4 w-4 mr-2" /> Produtos
              </Button>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { ArrowDownCircle, Loader2 } from 'lucide-react';
import { useSangria } from '@/hooks/useCaixa';
import { useToast } from '@/hooks/use-toast';

interface SangriaModalProps {
  open: boolean;
  onClose: () => void;
  sessionId: string;
}

export function SangriaModal({ open, onClose, sessionId }: SangriaModalProps) {
  const { toast } = useToast();
  const sangria = useSangria();
  const [amount, setAmount] = useState('');
  const [description, setDescription] = useState('');

  const handleSangria = async () => {
    const val = parseFloat(amount);
    if (isNaN(val) || val <= 0) {
      toast({ title: 'Valor inválido', variant: 'destructive' });
      return;
    }
    if (!description.trim()) {
      toast({ title: 'Informe o motivo', description: 'O motivo da sangria é obrigatório.', variant: 'destructive' });
      return;
    }

    try {
      await sangria.mutateAsync({
        sessionId,
        amount: val,
        description: description.trim(),
      });
      toast({ title: 'Sangria realizada!', description: `Retirada de R$ ${val.toLocaleString('pt-BR', { minimumFractionDigits: 2 })} registrada.` });
      setAmount('');
      setDescription('');
      onClose();
    } catch (err: any) {
      toast({ title: 'Erro ao realizar sangria', description: err.message, variant: 'destructive' });
    }
  };

  return (
    <Dialog open={open} onOpenChange={v => !v && onClose()}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-destructive">
            <ArrowDownCircle className="h-5 w-5" />
            Realizar Sangria
          </DialogTitle>
        </DialogHeader>
        <div className="space-y-4 py-4">
          <div className="space-y-2">
            <Label>Valor da Retirada</Label>
            <Input
              type="number"
              placeholder="0,00"
              value={amount}
              onChange={e => setAmount(e.target.value)}
              className="text-lg font-bold text-destructive"
              autoFocus
            />
          </div>
          <div className="space-y-2">
            <Label>Motivo / Observação</Label>
            <Textarea
              placeholder="Ex: Pagamento de fornecedor, retirada para depósito, etc."
              value={description}
              onChange={e => setDescription(e.target.value)}
              rows={3}
            />
          </div>
        </div>
        <DialogFooter>
          <Button variant="ghost" onClick={onClose} disabled={sangria.isPending}>Cancelar</Button>
          <Button 
            variant="destructive"
            onClick={handleSangria}
            disabled={sangria.isPending}
          >
            {sangria.isPending ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
            Confirmar Retirada
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { ArrowRight, Loader2, Lock } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Comanda, useComandas, useTransferOrders } from '@/hooks/useComandas';
import { useToast } from '@/hooks/use-toast';

interface TransferComandaModalProps {
  sourceComanda: Comanda;
  open: boolean;
  onClose: () => void;
}

export function TransferComandaModal({ sourceComanda, open, onClose }: TransferComandaModalProps) {
  const { toast } = useToast();
  const { data: comandasData, isLoading } = useComandas();
  const comandas = Array.isArray(comandasData) ? comandasData : [];
  const transferOrders = useTransferOrders();
  const [targetComanda, setTargetComanda] = useState<Comanda | null>(null);

  // List all other comandas
  const targetOptions = comandas.filter(c => c.id !== sourceComanda.id);

  const handleTransfer = async () => {
    if (!targetComanda) return;

    try {
      await transferOrders.mutateAsync({
        sourceComandaId: sourceComanda.id,
        targetComandaId: targetComanda.id,
        targetNumeroComanda: targetComanda.numero_comanda,
      });

      toast({
        title: 'Transferência concluída!',
        description: `Pedidos transferidos da Comanda #${sourceComanda.numero_comanda} para a #${targetComanda.numero_comanda}.`,
      });
      onClose();
    } catch (err: any) {
      toast({
        title: 'Erro na transferência',
        description: err.message,
        variant: 'destructive',
      });
    }
  };

  return (
    <Dialog open={open} onOpenChange={v => !v && onClose()}>
      <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Transferir Comanda #{sourceComanda.numero_comanda}</DialogTitle>
        </DialogHeader>

        <div className="space-y-4 py-4">
          <div className="bg-muted/50 p-4 rounded-lg flex items-center justify-between">
            <div className="text-center flex-1">
              <p className="text-xs text-muted-foreground uppercase font-semibold">Origem</p>
              <p className="text-lg font-bold">#{sourceComanda.numero_comanda}</p>
            </div>
            <ArrowRight className="h-5 w-5 text-muted-foreground" />
            <div className="text-center flex-1">
              <p className="text-xs text-muted-foreground uppercase font-semibold">Destino</p>
              {targetComanda ? (
                <p className="text-lg font-bold text-primary">#{targetComanda.numero_comanda}</p>
              ) : (
                <p className="text-sm text-muted-foreground italic">Selecione...</p>
              )}
            </div>
          </div>

          <div className="space-y-2">
            <h3 className="text-sm font-semibold text-muted-foreground uppercase">Selecione o Destino</h3>
            {isLoading ? (
              <div className="flex justify-center py-4">
                <Loader2 className="h-5 w-5 animate-spin text-primary" />
              </div>
            ) : targetOptions.length === 0 ? (
              <p className="text-sm text-muted-foreground text-center py-4">
                Nenhuma outra comanda disponível.
              </p>
            ) : (
              <div className="grid grid-cols-2 gap-2">
                {targetOptions.map(comanda => (
                  <Card
                    key={comanda.id}
                    className={`cursor-pointer hover:ring-2 hover:ring-primary/40 transition-all ${
                      targetComanda?.id === comanda.id ? 'ring-2 ring-primary bg-primary/5' : ''
                    }`}
                    onClick={() => setTargetComanda(comanda)}
                  >
                    <CardContent className="p-3 text-center">
                      <Lock className={`h-5 w-5 mx-auto mb-1 ${comanda.status === 'livre' ? 'text-green-500' : 'text-orange-400'}`} />
                      <p className="font-bold">#{comanda.numero_comanda}</p>
                      <Badge variant={comanda.status === 'livre' ? 'default' : 'secondary'} className="text-[10px] py-0">
                        {comanda.status === 'livre' ? 'Livre' : 'Ocupada'}
                      </Badge>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </div>

          <Button
            className="w-full"
            size="lg"
            disabled={!targetComanda || transferOrders.isPending}
            onClick={handleTransfer}
          >
            {transferOrders.isPending ? (
              <Loader2 className="h-4 w-4 animate-spin mr-2" />
            ) : null}
            Confirmar Transferência
          </Button>

          <Button variant="ghost" className="w-full" onClick={onClose}>
            Cancelar
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

