const loginSchema = z.object({
  email: z.string().trim().email({ message: 'Email inválido' }),
  password: z.string().min(6, { message: 'Senha deve ter pelo menos 6 caracteres' }),
});

const adminLoginSchema = z.object({
  email: z.string().trim().min(1, { message: 'Digite seu email ou usuário' }),
  password: z.string().min(6, { message: 'Senha deve ter pelo menos 6 caracteres' }),
});

type AuthMode = 'login' | 'signup' | 'forgot';

const Auth = () => {
  const navigate = useNavigate();
  const { toast } = useToast();
  const { user, login } = useAuth();
  const [mode, setMode] = useState<AuthMode>('login');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [formData, setFormData] = useState({ email: '', password: '' });

  useEffect(() => {
    if (user) {
      navigate('/admin');
    }
  }, [user, navigate]);

  const handleForgotPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      const emailValidation = z.string().email().safeParse(formData.email);
      if (!emailValidation.success) {
        toast({ title: 'Email inválido', description: 'Digite um email válido', variant: 'destructive' });
        setIsLoading(false);
        return;
      }

      // API integration for forgot password
      await api.post('/auth/forgot-password', { email: formData.email });
      toast({ title: 'Email enviado!', description: 'Se o email existir, você receberá um link de recuperação.' });
      setMode('login');
    } catch {
      toast({ title: 'Erro', description: 'Tente novamente mais tarde', variant: 'destructive' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleSignUp = async () => {
    setIsLoading(true);
    try {
      const validation = loginSchema.safeParse(formData);
      if (!validation.success) {
        toast({ title: 'Dados inválidos', description: validation.error.errors[0].message, variant: 'destructive' });
        setIsLoading(false);
        return;
      }

      await api.post('/auth/signup', { email: formData.email, password: formData.password });
      toast({ title: 'Conta criada!', description: 'Conta criada com sucesso. Verifique seu login.' });
      setMode('login');
    } catch (err: any) {
      toast({ title: 'Erro inesperado', description: err?.message || 'Tente novamente mais tarde', variant: 'destructive' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'forgot') return handleForgotPassword(e);
    if (mode === 'signup') return handleSignUp();

    setIsLoading(true);
    try {
      const validation = adminLoginSchema.safeParse(formData);
      if (!validation.success) {
        toast({ title: 'Dados inválidos', description: validation.error.errors[0].message, variant: 'destructive' });
        setIsLoading(false);
        return;
      }

      await login(formData.email.trim(), formData.password);
      toast({ title: 'Bem-vindo!', description: 'Login realizado com sucesso' });
    } catch (error: any) {
      toast({
        title: 'Erro ao entrar',
        description: error?.message || 'Usuário, email ou senha incorretos',
        variant: 'destructive',
      });
      setIsLoading(false);
    }
  };

  const titles: Record<AuthMode, string> = {
    login: 'Entrar no Painel',
    signup: 'Criar Conta',
    forgot: 'Recuperar Senha',
  };

  const subtitles: Record<AuthMode, string> = {
    login: 'Acesse sua conta para gerenciar pedidos',
    signup: 'Crie sua conta para começar a usar',
    forgot: 'Digite seu email para receber o link de recuperação',
  };

  return (
    <>
      <Helmet>
        <title>{titles[mode]} - Painel Admin</title>
      </Helmet>

      <div className="min-h-screen flex items-center justify-center p-4" style={{ backgroundColor: '#23354D' }}>
          <div className="w-full max-w-md">
            {/* Logo */}
            <div className="flex justify-center mb-8">
              <img
                src={logoInfornexa}
                alt="Logo do sistema"
                className="h-28 sm:h-36 w-auto drop-shadow-lg"
              />
            </div>

            {/* Card */}
            <div className="bg-card rounded-2xl shadow-xl p-8">
              {(mode === 'forgot' || mode === 'signup') && (
                <button
                  type="button"
                  onClick={() => setMode('login')}
                  className="flex items-center gap-1 text-muted-foreground hover:text-foreground text-sm mb-4"
                >
                  <ArrowLeft className="w-4 h-4" />
                  Voltar ao login
                </button>
              )}

              <h1 className="text-2xl font-bold text-center text-foreground mb-1">
                {titles[mode]}
              </h1>
              <p className="text-center text-muted-foreground text-sm mb-8">
                {subtitles[mode]}
              </p>

              <form onSubmit={handleSubmit} className="space-y-4">
                <div className="relative">
                  <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                  <Input
                    type="text"
                    placeholder={mode === 'login' ? 'Seu email ou usuário interno' : 'seu@email.com'}
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    className="pl-10 h-12 bg-muted/50 border-0 rounded-xl"
                  />
                </div>

                {(mode === 'login' || mode === 'signup') && (
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                    <Input
                      type={showPassword ? 'text' : 'password'}
                      placeholder={mode === 'signup' ? 'Crie uma senha (mín. 6 caracteres)' : 'Sua senha'}
                      value={formData.password}
                      onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                      className="pl-10 pr-10 h-12 bg-muted/50 border-0 rounded-xl"
                    />
                    <button
                      type="button"
