import { 
  Download, 
  Upload, 
  Loader2, 
  Database, 
  FileJson, 
  CheckCircle2, 
  AlertTriangle,
  ShoppingBag,
  Tag,
  Users,
  MapPin,
  Clock,
  Ticket,
  PlusCircle,
  Settings,
  Package,
  ClipboardList,
  UserCog,
  DollarSign,
  Trash2
} from 'lucide-react';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Progress } from '@/components/ui/progress';
import { supabase } from '@/integrations/supabase/client';
import { useToast } from '@/hooks/use-toast';

interface BackupData {
  version: string;
  created_at: string;
  store_config: any;
  categories: any[];
  products: any[];
  addon_groups: any[];
  addon_options: any[];
  product_addon_groups: any[];
  coupons: any[];
  delivery_zones: any[];
  business_hours: any[];
  user_roles: any[];
  customer_addresses: any[];
  // Inventory (NEW)
  ingredients: any[];
  product_ingredients: any[];
  // History & Orders (Report Data)
  orders: any[];
  order_items: any[];
  comandas: any[];
  comanda_pedidos: any[];
  comanda_vendas: any[];
  // Financial (NEW)
  caixa_sessions: any[];
  caixa_movimentacoes: any[];
  admin_users: any[];
}

const AdminBackup = () => {
  const { toast } = useToast();
  const [isExporting, setIsExporting] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [isResetting, setIsResetting] = useState(false);

  const handleResetData = async () => {
    if (!window.confirm('TEM CERTEZA ABSOLUTA?\n\nIsso irá APAGAR GERAL todos os pedidos, comandas, itens vendidos e sessões de caixa do sistema.\n\nEsta ação NÃO PODE SER DESFEITA.')) {
      return;
    }

    toast({
      title: 'Atenção',
      description: 'O recurso de reset no painel foi desativado. Apague os dados via phpMyAdmin (HostGator).',
      variant: 'destructive',
    });
  };
  const [progress, setProgress] = useState(0);
  const [importFile, setImportFile] = useState<File | null>(null);
  const [previewData, setPreviewData] = useState<BackupData | null>(null);

  const tables = [
    { name: 'store_config', label: 'Configurações da Loja', icon: Settings },
    { name: 'categories', label: 'Categorias', icon: Tag },
    { name: 'products', label: 'Produtos', icon: ShoppingBag },
    { name: 'addon_groups', label: 'Grupos de Acréscimos', icon: PlusCircle },
    { name: 'addon_options', label: 'Opções de Acréscimos', icon: PlusCircle },
    { name: 'product_addon_groups', label: 'Vínculos Produto-Acréscimo', icon: PlusCircle },
    { name: 'coupons', label: 'Cupons', icon: Ticket },
    { name: 'delivery_zones', label: 'Zonas de Entrega', icon: MapPin },
    { name: 'business_hours', label: 'Horários de Funcionamento', icon: Clock },
    { name: 'ingredients', label: 'Ingredientes (Estoque)', icon: Package },
    { name: 'product_ingredients', label: 'Composição de Produtos', icon: ClipboardList },
    { name: 'orders', label: 'Pedidos Delivery/Comandas', icon: Package },
    { name: 'order_items', label: 'Itens dos Pedidos', icon: ClipboardList },
    { name: 'comandas', label: 'Comandas Ativas', icon: Database },
    { name: 'comanda_vendas', label: 'Vendas de Comandas', icon: DollarSign },
    { name: 'caixa_sessions', label: 'Sessões de Caixa', icon: Database },
    { name: 'caixa_movimentacoes', label: 'Movimentações de Caixa', icon: DollarSign },
    { name: 'admin_users', label: 'Usuários Admin (Equipe)', icon: Users },
    { name: 'user_roles', label: 'Permissões de Usuário', icon: UserCog },
    { name: 'customer_addresses', label: 'Endereços de Clientes', icon: MapPin },
  ];

  const exportBackup = async () => {
    toast({
      title: 'Backup externo',
      description: 'Recomendamos usar o cPanel Hostgator / phpMyAdmin para backups completos de MySQL.',
    });
    setIsExporting(false);
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.name.endsWith('.json')) {
      toast({
        title: 'Arquivo inválido',
        description: 'Selecione um arquivo .json de backup.',
        variant: 'destructive',
      });
      return;
    }

    setImportFile(file);

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as BackupData;
        if (!data.version || !data.created_at) {
          throw new Error('Invalid backup format');
        }
        setPreviewData(data);
      } catch {
        toast({
          title: 'Arquivo inválido',
          description: 'O arquivo não é um backup válido.',
          variant: 'destructive',
        });
        setImportFile(null);
        setPreviewData(null);
      }
    };
    reader.readAsText(file);
  };

  const importBackup = async () => {
    if (!previewData) return;

    toast({
      title: 'Importação Bloqueada',
      description: 'Por segurança do MySQL, a importação direta via app foi desabilitada. Use o phpMyAdmin.',
      variant: 'destructive'
    });
    setIsImporting(false);
  };

  const cancelImport = () => {
    setImportFile(null);
    setPreviewData(null);
  };

  return (
    <AdminLayout title="Backup">
      <div className="space-y-6 max-w-4xl">
        {/* Header */}
        <div>
          <h2 className="text-2xl font-bold text-foreground">Backup do Sistema</h2>
          <p className="text-muted-foreground mt-1">
            Exporte ou importe todos os dados, incluindo histórico de vendas e relatórios
          </p>
        </div>

        {/* Export Section */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Download className="h-5 w-5 text-primary" />
              Exportar Backup Completo
            </CardTitle>
            <CardDescription>
              Gera um arquivo JSON com TODO o conteúdo do sistema: produtos, pedidos, comandas, caixa e estoque.
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
              {tables.map((table) => (
                <div
                  key={table.name}
                  className="flex items-center gap-2 text-sm text-muted-foreground bg-muted/50 rounded-lg px-3 py-2"
                >
                  <table.icon className="h-4 w-4" />
                  <span>{table.label}</span>
                </div>
              ))}
            </div>

            {isExporting && (
              <div className="space-y-2">
                <Progress value={progress} className="h-2" />
                <p className="text-sm text-muted-foreground text-center">
                  Exportando... {Math.round(progress)}%
                </p>
              </div>
            )}

            <Button
              onClick={exportBackup}
              disabled={isExporting}
              className="w-full sm:w-auto"
            >
              {isExporting ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Exportando...
                </>
              ) : (
                <>
                  <Download className="h-4 w-4 mr-2" />
                  Gerar Backup Completo
                </>
              )}
            </Button>
          </CardContent>
        </Card>

        {/* Import Section */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Upload className="h-5 w-5 text-primary" />
              Importar Backup
            </CardTitle>
            <CardDescription>
              Restaure o sistema a partir de um arquivo de backup completo.
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <Alert variant="destructive">
              <AlertTriangle className="h-4 w-4" />
              <AlertTitle>Risco de Perda de Dados!</AlertTitle>
              <AlertDescription>
                A importação irá <strong>sobrescrever todo o banco de dados</strong>.
              </AlertDescription>
            </Alert>

            {!previewData ? (
              <div className="border-2 border-dashed border-border rounded-xl p-8 text-center">
                <FileJson className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                <p className="text-muted-foreground mb-4">
                  Selecione um arquivo .json de backup
                </p>
                <label className="cursor-pointer">
                  <input
                    type="file"
                    accept=".json"
                    onChange={handleFileSelect}
                    className="hidden"
                  />
                  <Button variant="outline" asChild>
                    <span>
                      <Upload className="h-4 w-4 mr-2" />
                      Selecionar Arquivo
                    </span>
                  </Button>
                </label>
              </div>
            ) : (
              <div className="space-y-4">
                <Alert>
                  <CheckCircle2 className="h-4 w-4" />
                  <AlertTitle>Arquivo: {importFile?.name}</AlertTitle>
                  <AlertDescription>
                    Criado em {format(new Date(previewData.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                  </AlertDescription>
                </Alert>

                <div className="bg-muted/50 rounded-xl p-4 space-y-3">
                  <h4 className="font-medium text-foreground">Conteúdo do Backup:</h4>
                  <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 text-sm">
                    <div className="flex items-center justify-between bg-background rounded-lg px-3 py-2">
                      <span className="text-muted-foreground">Produtos</span>
                      <span className="font-medium">{previewData.products?.length || 0}</span>
                    </div>
                    <div className="flex items-center justify-between bg-background rounded-lg px-3 py-2 border-2 border-primary/30">
                      <span className="text-muted-foreground font-semibold">Vendas (Relatórios)</span>
                      <span className="font-bold text-primary">{previewData.orders?.length || 0}</span>
                    </div>
                    <div className="flex items-center justify-between bg-background rounded-lg px-3 py-2">
                      <span className="text-muted-foreground">Comandas</span>
                      <span className="font-medium">{previewData.comandas?.length || 0}</span>
                    </div>
                    <div className="flex items-center justify-between bg-background rounded-lg px-3 py-2">
                      <span className="text-muted-foreground">Caixa</span>
                      <span className="font-medium">{previewData.caixa_sessions?.length || 0}</span>
                    </div>
                    <div className="flex items-center justify-between bg-background rounded-lg px-3 py-2">
                      <span className="text-muted-foreground">Estoque</span>
                      <span className="font-medium">{previewData.ingredients?.length || 0}</span>
                    </div>
                    <div className="flex items-center justify-between bg-background rounded-lg px-3 py-2">
                      <span className="text-muted-foreground">Zonas</span>
                      <span className="font-medium">{previewData.delivery_zones?.length || 0}</span>
                    </div>
                  </div>
                </div>

                {isImporting && (
                  <div className="space-y-2">
                    <Progress value={progress} className="h-2" />
                    <p className="text-sm text-muted-foreground text-center">
                      Restaurando... {Math.round(progress)}%
                    </p>
                  </div>
                )}

                <div className="flex gap-3">
                  <Button
                    onClick={importBackup}
                    disabled={isImporting}
                    variant="destructive"
                    className="flex-1"
                  >
                    {isImporting ? (
                      <>
                        <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                        Restaurando...
                      </>
                    ) : (
                      <>
                        <Upload className="h-4 w-4 mr-2" />
                        Substituir Dados Agora
                      </>
                    )}
                  </Button>
                  <Button
                    onClick={cancelImport}
                    disabled={isImporting}
                    variant="outline"
                  >
                    Cancelar
                  </Button>
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Reset Section */}
        <Card className="border-destructive/50">
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-destructive">
              <Trash2 className="h-5 w-5" />
              Apagar Registros
            </CardTitle>
            <CardDescription>
              Apaga apenas as transações (pedidos, itens, comandas, caixa), mantendo os produtos, estoque e configurações intactos.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Alert variant="destructive" className="mb-4">
              <AlertTriangle className="h-4 w-4" />
              <AlertTitle>Cuidado MÁXIMO!</AlertTitle>
              <AlertDescription>
                Esta ação apagará permanentemente todo o histórico de vendas. É recomendado gerar um Backup Completo antes de prosseguir.
              </AlertDescription>
            </Alert>
            <Button
              onClick={handleResetData}
              disabled={isResetting || isExporting || isImporting}
              variant="destructive"
              className="w-full sm:w-auto"
            >
              {isResetting ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Apagando...
                </>
              ) : (
                <>
                  <Trash2 className="h-4 w-4 mr-2" />
                  Apagar geral
                </>
              )}
            </Button>
          </CardContent>
        </Card>

        {/* Info */}
        <Card className="bg-muted/30 border-primary/20">
          <CardContent className="pt-6">
            <h4 className="font-bold text-primary mb-2 flex items-center gap-2">
              <CheckCircle2 className="h-5 w-5" />
              Backup Total (com Relatórios)
            </h4>
            <ul className="text-sm text-muted-foreground space-y-2">
              <li>• <strong>Relatórios e Vendas</strong>: Histórico de todos os pedidos e itens vendidos.</li>
              <li>• <strong>Financeiro (Caixa)</strong>: Sessões abertas/fechadas e todas as entradas/saídas.</li>
              <li>• <strong>Estoque Completo</strong>: Ingredientes, produtos e fichas técnicas (composições).</li>
              <li>• <strong>Equipe e Acessos</strong>: Usuários do painel admin e suas permissões configuradas.</li>
              <li>• <strong>Configurações</strong>: Produtos, categorias, taxas de entrega e horários.</li>
            </ul>
          </CardContent>
        </Card>
      </div>
    </AdminLayout>
  );
};

export default AdminBackup;

import { useState } from 'react';
import { Plus, Pencil, Trash2, Loader2, GripVertical } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { useCategories, useCreateCategory, useUpdateCategory, useDeleteCategory, useReorderCategories, Category } from '@/hooks/useCategories';
import { useToast } from '@/hooks/use-toast';
import { ImageUpload } from '@/components/admin/ImageUpload';
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  DragEndEvent,
} from '@dnd-kit/core';
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  useSortable,
  verticalListSortingStrategy,
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { cn } from '@/lib/utils';

interface SortableCategoryItemProps {
  category: Category;
  onEdit: (category: Category) => void;
  onDelete: (category: Category) => void;
}

function SortableCategoryItem({ category, onEdit, onDelete }: SortableCategoryItemProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: category.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={cn(
        "flex items-center gap-2 sm:gap-4 p-3 sm:p-4 border-b border-border last:border-0 bg-card",
        isDragging && "opacity-50 shadow-lg z-50"
      )}
    >
      <button
        {...attributes}
        {...listeners}
        className="cursor-grab active:cursor-grabbing touch-none p-1 rounded hover:bg-muted flex-shrink-0"
        aria-label="Arrastar para reordenar"
      >
        <GripVertical className="h-4 w-4 sm:h-5 sm:w-5 text-muted-foreground" />
      </button>

      <div className="flex-1 min-w-0">
        <p className="font-medium text-foreground text-sm sm:text-base truncate">{category.name}</p>
        <p className="text-xs text-muted-foreground">Ordem: {category.sort_order}</p>
      </div>

      <div className="flex gap-1 sm:gap-2 flex-shrink-0">
        <Button variant="action-icon" size="icon" className="h-8 w-8 sm:h-10 sm:w-10" onClick={() => onEdit(category)}>
          <Pencil className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
        </Button>
        <Button variant="action-icon-destructive" size="icon" className="h-8 w-8 sm:h-10 sm:w-10" onClick={() => onDelete(category)}>
          <Trash2 className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
        </Button>
      </div>
    </div>
  );
}

const AdminCategories = () => {
  const { data: categories, isLoading } = useCategories();
  const createCategory = useCreateCategory();
  const updateCategory = useUpdateCategory();
  const deleteCategory = useDeleteCategory();
  const reorderCategories = useReorderCategories();
  const { toast } = useToast();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    sort_order: 0,
    image_url: null as string | null,
  });

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 8,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const openCreateModal = () => {
    setEditingCategory(null);
    setFormData({
      name: '',
      sort_order: (categories?.length || 0) + 1,
      image_url: null,
    });
    setIsModalOpen(true);
  };

  const openEditModal = (category: Category) => {
    setEditingCategory(category);
    setFormData({
      name: category.name,
      sort_order: category.sort_order,
      image_url: category.image_url || null,
    });
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name.trim()) {
      toast({ title: 'Nome é obrigatório', variant: 'destructive' });
      return;
    }

    try {
      if (editingCategory) {
        await updateCategory.mutateAsync({
          id: editingCategory.id,
          name: formData.name,
          sort_order: formData.sort_order,
          image_url: formData.image_url,
        });
        toast({ title: 'Categoria atualizada!' });
      } else {
        await createCategory.mutateAsync({
          name: formData.name,
          sort_order: formData.sort_order,
          image_url: formData.image_url,
        });
        toast({ title: 'Categoria criada!' });
      }

      setIsModalOpen(false);
    } catch (error: any) {
      toast({ title: 'Erro ao salvar', description: error.message, variant: 'destructive' });
    }
  };

  const handleDelete = async (category: Category) => {
    if (!confirm(`Deseja excluir "${category.name}"? Os produtos desta categoria ficarão sem categoria.`)) return;

    try {
      await deleteCategory.mutateAsync(category.id);
      toast({ title: 'Categoria excluída!' });
    } catch (error: any) {
      toast({ title: 'Erro ao excluir', description: error.message, variant: 'destructive' });
    }
  };

  const handleDragEnd = async (event: DragEndEvent) => {
    const { active, over } = event;

    if (!over || active.id === over.id || !categories) return;

    const oldIndex = categories.findIndex((c) => c.id === active.id);
    const newIndex = categories.findIndex((c) => c.id === over.id);

    const reorderedCategories = arrayMove(categories, oldIndex, newIndex);
    const orderedIds = reorderedCategories.map((c) => c.id);

    try {
      await reorderCategories.mutateAsync(orderedIds);
      toast({ title: 'Ordem atualizada!' });
    } catch (error) {
      toast({ title: 'Erro ao reordenar', variant: 'destructive' });
    }
  };

  if (isLoading) {
    return (
      <AdminLayout title="Categorias">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout title="Categorias">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 mb-4 sm:mb-6">
        <div>
          <p className="text-sm text-muted-foreground">
            {categories?.length || 0} categorias cadastradas
          </p>
          <p className="text-xs text-muted-foreground mt-1">
            Arraste para reordenar
          </p>
        </div>
        <Button onClick={openCreateModal} className="w-full sm:w-auto">
          <Plus className="h-4 w-4 mr-2" />
          Nova Categoria
        </Button>
      </div>

      {/* Categories List */}
      <div className="bg-card rounded-xl shadow-card overflow-hidden">
        {categories && categories.length > 0 ? (
          <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            onDragEnd={handleDragEnd}
          >
            <SortableContext
              items={categories.map((c) => c.id)}
              strategy={verticalListSortingStrategy}
            >
              {categories.map((category) => (
                <SortableCategoryItem
                  key={category.id}
                  category={category}
                  onEdit={openEditModal}
                  onDelete={handleDelete}
                />
              ))}
            </SortableContext>
          </DndContext>
        ) : (
          <div className="py-12 text-center">
            <p className="text-muted-foreground">Nenhuma categoria cadastrada</p>
          </div>
        )}
      </div>

      {/* Create/Edit Modal */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>
              {editingCategory ? 'Editar Categoria' : 'Nova Categoria'}
            </DialogTitle>
          </DialogHeader>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="text-sm text-muted-foreground">Nome *</label>
              <Input
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                placeholder="Nome da categoria"
                className="mt-1"
              />
            </div>

            <div>
              <label className="text-sm text-muted-foreground">Imagem da categoria</label>
              <ImageUpload
                bucket="store-assets"
                currentUrl={formData.image_url}
                onUpload={(url) => setFormData({ ...formData, image_url: url })}
                onRemove={() => setFormData({ ...formData, image_url: null })}
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">
                Opcional — sem imagem será usado um gradiente colorido
              </p>
            </div>

            <div className="flex justify-end gap-2 pt-4">
              <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)}>
                Cancelar
              </Button>
              <Button type="submit" disabled={createCategory.isPending || updateCategory.isPending}>
                {(createCategory.isPending || updateCategory.isPending) && (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                )}
                {editingCategory ? 'Salvar' : 'Criar'}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </AdminLayout>
  );
};

export default AdminCategories;

import { useState } from 'react';
import { Plus, Trash2, Hash, Loader2, Receipt } from 'lucide-react';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { useComandas, useCreateComanda, useDeleteComanda } from '@/hooks/useComandas';

const AdminComandas = () => {
  const { toast } = useToast();
  const { data: comandas = [], isLoading: loadingComandas } = useComandas();
  const createComanda = useCreateComanda();
  const deleteComanda = useDeleteComanda();

  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newNumero, setNewNumero] = useState('');

  const handleCreateComanda = async () => {
    const num = parseInt(newNumero);
    if (isNaN(num) || num <= 0) {
      toast({ title: 'Número inválido', description: 'Informe um número válido.', variant: 'destructive' });
      return;
    }
    try {
      await createComanda.mutateAsync(num);
      toast({ title: 'Comanda criada', description: `Comanda #${num} criada com sucesso.` });
      setNewNumero('');
      setShowCreateForm(false);
    } catch (err: any) {
      toast({
        title: 'Erro',
        description: err.message?.includes('unique') ? 'Já existe uma comanda com esse número.' : err.message,
        variant: 'destructive',
      });
    }
  };

  const handleDeleteComanda = async (comandaId: string, numero: number) => {
    try {
      await deleteComanda.mutateAsync(comandaId);
      toast({ title: 'Comanda excluída', description: `Comanda #${numero} removida.` });
    } catch (err: any) {
      toast({ title: 'Erro', description: err.message, variant: 'destructive' });
    }
  };

  return (
    <AdminLayout title="Gerenciar Comandas">
      <div className="max-w-4xl mx-auto space-y-6">
        <Card className="admin-card border-none shadow-xl">
          <CardHeader className="bg-primary/5 pb-4">
            <CardTitle className="flex items-center gap-3 text-lg font-bold">
              <div className="p-2 bg-primary/20 rounded-lg text-primary">
                <Hash className="h-5 w-5" />
              </div>
              Controle de Comandas
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-6 pt-6">
            {!showCreateForm ? (
              <Button onClick={() => setShowCreateForm(true)} className="w-full" size="lg">
                <Plus className="h-5 w-5 mr-2" />
                Criar Nova Comanda
              </Button>
            ) : (
              <div className="flex gap-3 flex-col sm:flex-row">
                <Input
                  type="number"
                  placeholder="Informe o número da comanda"
                  value={newNumero}
                  onChange={e => setNewNumero(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleCreateComanda()}
                  className="h-12 text-lg"
                  autoFocus
                />
                <div className="flex gap-2">
                  <Button onClick={handleCreateComanda} disabled={createComanda.isPending} size="lg" className="flex-1">
                    {createComanda.isPending ? <Loader2 className="h-5 w-5 animate-spin" /> : 'Criar'}
                  </Button>
                  <Button variant="ghost" onClick={() => { setShowCreateForm(false); setNewNumero(''); }} size="lg">
                    Cancelar
                  </Button>
                </div>
              </div>
            )}

            <div className="border-t border-border pt-6">
              <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider mb-4">
                Comandas Cadastradas ({comandas.length})
              </h3>

              {loadingComandas ? (
                <div className="flex justify-center py-12">
                  <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
              ) : comandas.length === 0 ? (
                <div className="py-12 text-center bg-muted/20 rounded-2xl border-2 border-dashed border-border/50">
                  <Receipt className="h-12 w-12 mx-auto text-muted-foreground/30 mb-3" />
                  <p className="text-muted-foreground">Nenhuma comanda criada até o momento.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {comandas.map(comanda => (
                    <div 
                      key={comanda.id} 
                      className="flex items-center justify-between p-4 rounded-2xl bg-muted/40 border border-border/50 hover:bg-muted/60 transition-colors"
                    >
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-primary/10 rounded-lg text-primary">
                          <Receipt className="h-5 w-5" />
                        </div>
                        <div>
                          <p className="font-bold text-lg">Comanda #{comanda.numero_comanda}</p>
                          <Badge variant={comanda.status === 'livre' ? 'default' : 'destructive'} className="text-[10px] uppercase font-bold px-2 py-0">
                            {comanda.status === 'livre' ? 'Livre' : 'Ocupada'}
                          </Badge>
                        </div>
                      </div>

                      {comanda.status === 'livre' && (
                        <Button
                          variant="action-icon-destructive"
                          size="icon"
                          onClick={() => handleDeleteComanda(comanda.id, comanda.numero_comanda)}
                          disabled={deleteComanda.isPending}
                          title="Excluir comanda"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </AdminLayout>
  );
};

export default AdminComandas;

import { useState } from 'react';
import { Plus, Pencil, Trash2, Loader2, Ticket, ToggleLeft, ToggleRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { useCoupons, useCreateCoupon, useUpdateCoupon, useDeleteCoupon, Coupon } from '@/hooks/useCoupons';
import { useToast } from '@/hooks/use-toast';

const AdminCoupons = () => {
  const { data: coupons, isLoading } = useCoupons();
  const createCoupon = useCreateCoupon();
  const updateCoupon = useUpdateCoupon();
  const deleteCoupon = useDeleteCoupon();
  const { toast } = useToast();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCoupon, setEditingCoupon] = useState<Coupon | null>(null);
  const [formData, setFormData] = useState({
    code: '',
    discount_type: 'percentage' as 'percentage' | 'fixed',
    discount_value: '',
    min_order_value: '',
    max_uses: '',
    expires_at: '',
    is_active: true,
  });

  const formatCurrency = (value: number) =>
    Number(value).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  const openCreateModal = () => {
    setEditingCoupon(null);
    setFormData({
      code: '',
      discount_type: 'percentage',
      discount_value: '',
      min_order_value: '',
      max_uses: '',
      expires_at: '',
      is_active: true,
    });
    setIsModalOpen(true);
  };

  const openEditModal = (coupon: Coupon) => {
    setEditingCoupon(coupon);
    setFormData({
      code: coupon.code,
      discount_type: coupon.discount_type as 'percentage' | 'fixed',
      discount_value: coupon.discount_value.toString(),
      min_order_value: coupon.min_order_value?.toString() || '',
      max_uses: coupon.max_uses?.toString() || '',
      expires_at: coupon.expires_at ? coupon.expires_at.split('T')[0] : '',
      is_active: coupon.is_active,
    });
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.code.trim()) {
      toast({ title: 'Código é obrigatório', variant: 'destructive' });
      return;
    }

    const discountValue = parseFloat(formData.discount_value.replace(',', '.'));
    if (isNaN(discountValue) || discountValue <= 0) {
      toast({ title: 'Valor do desconto inválido', variant: 'destructive' });
      return;
    }

    try {
      const couponData = {
        code: formData.code.toUpperCase(),
        discount_type: formData.discount_type,
        discount_value: discountValue,
        min_order_value: formData.min_order_value ? parseFloat(formData.min_order_value.replace(',', '.')) : 0,
        max_uses: formData.max_uses ? parseInt(formData.max_uses) : null,
        expires_at: formData.expires_at ? new Date(formData.expires_at).toISOString() : null,
        is_active: formData.is_active,
      };

      if (editingCoupon) {
        await updateCoupon.mutateAsync({ id: editingCoupon.id, ...couponData });
        toast({ title: 'Cupom atualizado!' });
      } else {
        await createCoupon.mutateAsync(couponData);
        toast({ title: 'Cupom criado!' });
      }

      setIsModalOpen(false);
    } catch (error: any) {
      toast({ title: 'Erro ao salvar', description: error.message, variant: 'destructive' });
    }
  };

  const handleDelete = async (coupon: Coupon) => {
    if (!confirm(`Deseja excluir o cupom "${coupon.code}"?`)) return;

    try {
      await deleteCoupon.mutateAsync(coupon.id);
      toast({ title: 'Cupom excluído!' });
    } catch (error: any) {
      toast({ title: 'Erro ao excluir', description: error.message, variant: 'destructive' });
    }
  };

  const toggleActive = async (coupon: Coupon) => {
    try {
      await updateCoupon.mutateAsync({
        id: coupon.id,
        is_active: !coupon.is_active,
      });
      toast({ title: coupon.is_active ? 'Cupom desativado' : 'Cupom ativado' });
    } catch (error) {
      toast({ title: 'Erro ao atualizar', variant: 'destructive' });
    }
  };

  const getDiscountDisplay = (coupon: Coupon) => {
    if (coupon.discount_type === 'percentage') {
      return `${coupon.discount_value}%`;
    }
    return formatCurrency(coupon.discount_value);
  };

  if (isLoading) {
    return (
      <AdminLayout title="Cupons">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout title="Cupons">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 mb-4 sm:mb-6">
        <p className="text-sm text-muted-foreground">
          {coupons?.length || 0} cupons cadastrados
        </p>
        <Button onClick={openCreateModal} className="w-full sm:w-auto">
          <Plus className="h-4 w-4 mr-2" />
          Novo Cupom
        </Button>
      </div>

      {/* Coupons Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 sm:gap-4">
        {coupons?.map((coupon) => (
          <div 
            key={coupon.id}
            className="bg-card rounded-xl p-3 sm:p-4 shadow-card"
          >
            <div className="flex items-start justify-between gap-2 mb-3">
              <div className="flex items-center gap-2 min-w-0">
                <div className="h-8 w-8 sm:h-10 sm:w-10 rounded-lg bg-primary/10 flex items-center justify-center flex-shrink-0">
                  <Ticket className="h-4 w-4 sm:h-5 sm:w-5 text-primary" />
                </div>
                <div className="min-w-0">
                  <p className="font-bold text-foreground text-sm sm:text-base truncate">{coupon.code}</p>
                  <p className="text-lg sm:text-2xl font-bold text-primary">{getDiscountDisplay(coupon)}</p>
                </div>
              </div>
              <Badge variant={coupon.is_active ? 'open' : 'closed'} className="text-[10px] sm:text-xs flex-shrink-0">
                {coupon.is_active ? 'Ativo' : 'Inativo'}
              </Badge>
            </div>

            <div className="space-y-1 text-xs sm:text-sm text-muted-foreground mb-3 sm:mb-4">
              {coupon.min_order_value > 0 && (
                <p>Mínimo: {formatCurrency(coupon.min_order_value)}</p>
              )}
              {coupon.max_uses && (
                <p>Usos: {coupon.current_uses}/{coupon.max_uses}</p>
              )}
              {coupon.expires_at && (
                <p>Expira: {new Date(coupon.expires_at).toLocaleDateString('pt-BR')}</p>
              )}
            </div>

            <div className="flex gap-2">
              <Button 
                variant="outline" 
                size="sm" 
                className="flex-1 text-xs sm:text-sm h-8 sm:h-9"
                onClick={() => toggleActive(coupon)}
              >
                {coupon.is_active ? (
                  <><ToggleRight className="h-3.5 w-3.5 sm:h-4 sm:w-4 mr-1" /> <span className="hidden xs:inline">Desativar</span><span className="xs:hidden">Off</span></>
                ) : (
                  <><ToggleLeft className="h-3.5 w-3.5 sm:h-4 sm:w-4 mr-1" /> <span className="hidden xs:inline">Ativar</span><span className="xs:hidden">On</span></>
                )}
              </Button>
              <Button variant="action-icon" size="icon" className="h-8 w-8 sm:h-9 sm:w-9" onClick={() => openEditModal(coupon)}>
                <Pencil className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
              </Button>
              <Button variant="action-icon-destructive" size="icon" className="h-8 w-8 sm:h-9 sm:w-9" onClick={() => handleDelete(coupon)}>
                <Trash2 className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
              </Button>
            </div>
          </div>
        ))}

        {(!coupons || coupons.length === 0) && (
          <div className="col-span-full py-12 text-center">
            <Ticket className="h-12 w-12 mx-auto mb-4 text-muted-foreground" />
            <p className="text-muted-foreground">Nenhum cupom cadastrado</p>
          </div>
        )}
      </div>

      {/* Create/Edit Modal */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>
              {editingCoupon ? 'Editar Cupom' : 'Novo Cupom'}
            </DialogTitle>
          </DialogHeader>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="text-sm text-muted-foreground">Código *</label>
              <Input
                value={formData.code}
                onChange={(e) => setFormData({ ...formData, code: e.target.value.toUpperCase() })}
                placeholder="PROMO10"
                className="mt-1"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm text-muted-foreground">Tipo</label>
                <Select
                  value={formData.discount_type}
                  onValueChange={(value: 'percentage' | 'fixed') => 
                    setFormData({ ...formData, discount_type: value })
                  }
                >
                  <SelectTrigger className="mt-1">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="percentage">Porcentagem</SelectItem>
                    <SelectItem value="fixed">Valor Fixo</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div>
                <label className="text-sm text-muted-foreground">
                  Valor {formData.discount_type === 'percentage' ? '(%)' : '(R$)'} *
                </label>
                <Input
                  value={formData.discount_value}
                  onChange={(e) => setFormData({ ...formData, discount_value: e.target.value })}
                  placeholder={formData.discount_type === 'percentage' ? '10' : '5,00'}
                  className="mt-1"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm text-muted-foreground">Pedido Mínimo (R$)</label>
                <Input
                  value={formData.min_order_value}
                  onChange={(e) => setFormData({ ...formData, min_order_value: e.target.value })}
                  placeholder="0,00"
                  className="mt-1"
                />
              </div>
              <div>
                <label className="text-sm text-muted-foreground">Máx. Usos</label>
                <Input
                  type="number"
                  value={formData.max_uses}
                  onChange={(e) => setFormData({ ...formData, max_uses: e.target.value })}
                  placeholder="Ilimitado"
                  className="mt-1"
                />
              </div>
            </div>

            <div>
              <label className="text-sm text-muted-foreground">Data de Expiração</label>
              <Input
                type="date"
                value={formData.expires_at}
                onChange={(e) => setFormData({ ...formData, expires_at: e.target.value })}
                className="mt-1"
              />
            </div>

            <div className="flex justify-end gap-2 pt-4">
              <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)}>
                Cancelar
              </Button>
              <Button type="submit" disabled={createCoupon.isPending || updateCoupon.isPending}>
                {(createCoupon.isPending || updateCoupon.isPending) && (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                )}
                {editingCoupon ? 'Salvar' : 'Criar'}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </AdminLayout>
  );
};

export default AdminCoupons;

import { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Progress } from '@/components/ui/progress';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { supabase } from '@/integrations/supabase/client';
import { api } from '@/lib/api';
import { useQuery } from '@tanstack/react-query';
import { 
  DollarSign, 
  TrendingUp, 
  TrendingDown,
  ShoppingBag, 
  Clock, 
  Truck, 
  Store, 
  Loader2,
  Users,
  ChefHat,
  Utensils,
