                <CardContent>
                  {stats.topProducts.length === 0 ? (
                    <div className="py-8 text-center text-muted-foreground">
                      <ShoppingBag className="w-12 h-12 mx-auto mb-2 opacity-30" />
                      <p>Nenhum produto vendido no período</p>
