                  )}
                </CardContent>
              </Card>
            </div>

          </>
        )}
      </div>
    </AdminLayout>
  );
}

import { useState, useEffect } from 'react';
import { Helmet } from 'react-helmet-async';
import { Plus, Edit, Trash2, MapPin, Loader2, ToggleLeft, ToggleRight, Truck, Clock, ShoppingBag } from 'lucide-react';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { useDeliveryZones, DeliveryZone } from '@/hooks/useDeliveryZones';
import { useStoreConfig, useUpdateStoreConfig } from '@/hooks/useStore';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { useToast } from '@/hooks/use-toast';

export default function DeliveryZones() {
  const { zones, isLoading, createZone, updateZone, deleteZone } = useDeliveryZones();
  const { data: store, isLoading: isLoadingStore } = useStoreConfig();
  const updateStore = useUpdateStoreConfig();
  const { toast } = useToast();

  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingZone, setEditingZone] = useState<DeliveryZone | null>(null);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    fee: '',
    min_order_value: '',
    is_active: true,
  });

  // Delivery settings form
  const [deliverySettings, setDeliverySettings] = useState({
    delivery_fee: '',
    delivery_time_min: '',
    delivery_time_max: '',
    min_order_value: '',
  });

  useEffect(() => {
    if (store) {
      setDeliverySettings({
        delivery_fee: store.delivery_fee?.toString() || '',
        delivery_time_min: store.delivery_time_min?.toString() || '30',
        delivery_time_max: store.delivery_time_max?.toString() || '45',
        min_order_value: store.min_order_value?.toString() || '',
      });
    }
  }, [store]);

  const deliveryFeeMode = store?.delivery_fee_mode || 'fixed';

  const handleOpenCreate = () => {
    setEditingZone(null);
    setFormData({ name: '', fee: '', min_order_value: '', is_active: true });
    setIsDialogOpen(true);
  };

  const handleOpenEdit = (zone: DeliveryZone) => {
    setEditingZone(zone);
    setFormData({
      name: zone.name,
      fee: zone.fee.toString(),
      min_order_value: zone.min_order_value?.toString() || '',
      is_active: zone.is_active,
    });
    setIsDialogOpen(true);
  };

  const handleSubmit = async () => {
    const payload = {
      name: formData.name.trim(),
      fee: parseFloat(formData.fee) || 0,
      min_order_value: formData.min_order_value ? parseFloat(formData.min_order_value) : null,
      is_active: formData.is_active,
      sort_order: editingZone ? editingZone.sort_order : zones.length,
    };

    if (editingZone) {
      await updateZone.mutateAsync({ id: editingZone.id, ...payload });
    } else {
      await createZone.mutateAsync(payload);
    }

    setIsDialogOpen(false);
  };

  const handleDelete = async () => {
    if (deleteId) {
      await deleteZone.mutateAsync(deleteId);
      setDeleteId(null);
    }
  };

  const handleModeChange = async (mode: string) => {
    if (store?.id) {
      await updateStore.mutateAsync({ id: store.id, delivery_fee_mode: mode as 'fixed' | 'zones' });
    }
  };

  const handleSaveDeliverySettings = async () => {
    if (!store?.id) return;
    try {
      await updateStore.mutateAsync({
        id: store.id,
        delivery_fee: parseFloat(deliverySettings.delivery_fee.replace(',', '.')) || 0,
        delivery_time_min: parseInt(deliverySettings.delivery_time_min) || 30,
        delivery_time_max: parseInt(deliverySettings.delivery_time_max) || 45,
        min_order_value: parseFloat(deliverySettings.min_order_value.replace(',', '.')) || 0,
      });
      toast({ title: 'Configurações de entrega salvas!' });
    } catch (error: any) {
      toast({ title: 'Erro ao salvar', description: error.message, variant: 'destructive' });
    }
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);
  };

  if (isLoading) {
    return (
      <AdminLayout title="Taxas de Entrega">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout title="Taxas de Entrega">
      <Helmet>
        <title>Taxas de Entrega - Admin</title>
      </Helmet>

      <div className="space-y-6">
        {/* Configurações Gerais de Entrega */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Truck className="h-5 w-5" />
              Configurações de Entrega
            </CardTitle>
            <CardDescription>
              Configure taxa, tempo de entrega e pedido mínimo
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="delivery_fee" className="flex items-center gap-2">
                  <Truck className="h-4 w-4 text-muted-foreground" />
                  Taxa de Entrega (R$)
                </Label>
                <Input
                  id="delivery_fee"
                  value={deliverySettings.delivery_fee}
                  onChange={(e) => setDeliverySettings({ ...deliverySettings, delivery_fee: e.target.value })}
                  placeholder="5,00"
                />
                <p className="text-xs text-muted-foreground">Usada quando o modo for Taxa Fixa</p>
              </div>

              <div className="space-y-2">
                <Label htmlFor="min_order_value" className="flex items-center gap-2">
                  <ShoppingBag className="h-4 w-4 text-muted-foreground" />
                  Pedido Mínimo (R$)
                </Label>
                <Input
                  id="min_order_value"
                  value={deliverySettings.min_order_value}
                  onChange={(e) => setDeliverySettings({ ...deliverySettings, min_order_value: e.target.value })}
                  placeholder="20,00"
                />
                <p className="text-xs text-muted-foreground">Valor mínimo para aceitar pedidos</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="delivery_time_min" className="flex items-center gap-2">
                  <Clock className="h-4 w-4 text-muted-foreground" />
                  Tempo Mínimo (min)
                </Label>
                <Input
                  id="delivery_time_min"
                  type="number"
                  value={deliverySettings.delivery_time_min}
                  onChange={(e) => setDeliverySettings({ ...deliverySettings, delivery_time_min: e.target.value })}
                  placeholder="30"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="delivery_time_max" className="flex items-center gap-2">
                  <Clock className="h-4 w-4 text-muted-foreground" />
                  Tempo Máximo (min)
                </Label>
                <Input
                  id="delivery_time_max"
                  type="number"
                  value={deliverySettings.delivery_time_max}
                  onChange={(e) => setDeliverySettings({ ...deliverySettings, delivery_time_max: e.target.value })}
                  placeholder="45"
                />
              </div>
            </div>
            <p className="text-xs text-muted-foreground">
              Exibido como "{deliverySettings.delivery_time_min || 30}-{deliverySettings.delivery_time_max || 45} min" no cardápio
            </p>

            <Button 
              onClick={handleSaveDeliverySettings} 
              className="w-full"
              disabled={updateStore.isPending}
            >
              {updateStore.isPending ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Salvando...
                </>
              ) : (
                'Salvar Configurações'
              )}
            </Button>
          </CardContent>
        </Card>

        {/* Modo de Taxa */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <MapPin className="h-5 w-5" />
              Modo de Cobrança
            </CardTitle>
            <CardDescription>
              Escolha como será calculada a taxa de entrega
            </CardDescription>
          </CardHeader>
          <CardContent>
            <RadioGroup 
              value={deliveryFeeMode} 
              onValueChange={handleModeChange}
              className="grid gap-4 sm:grid-cols-2"
            >
              <Label 
                htmlFor="fixed" 
                className={`flex items-start gap-3 p-4 border rounded-xl cursor-pointer transition-colors ${deliveryFeeMode === 'fixed' ? 'border-primary bg-primary/5' : 'border-border hover:bg-muted/50'}`}
              >
                <RadioGroupItem value="fixed" id="fixed" className="mt-1" />
                <div>
                  <p className="font-medium">Taxa Fixa</p>
                  <p className="text-sm text-muted-foreground">
                    Valor único para todas as entregas ({formatCurrency(store?.delivery_fee || 0)})
                  </p>
                </div>
              </Label>

              <Label 
                htmlFor="zones" 
                className={`flex items-start gap-3 p-4 border rounded-xl cursor-pointer transition-colors ${deliveryFeeMode === 'zones' ? 'border-primary bg-primary/5' : 'border-border hover:bg-muted/50'}`}
              >
                <RadioGroupItem value="zones" id="zones" className="mt-1" />
                <div>
                  <p className="font-medium">Por Bairro/CEP/Setor</p>
                  <p className="text-sm text-muted-foreground">
                    Taxa diferente para cada bairro, CEP ou setor
                  </p>
                </div>
              </Label>
            </RadioGroup>
          </CardContent>
        </Card>

        {/* Lista de Zonas */}
        {deliveryFeeMode === 'zones' && (
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <div>
                <CardTitle>Entrega</CardTitle>
                <CardDescription>
                  Configure a taxa para cada bairro, CEP ou setor
                </CardDescription>
              </div>
              <Button onClick={handleOpenCreate}>
                <Plus className="h-4 w-4 mr-2" />
                Novo Local
              </Button>
            </CardHeader>
            <CardContent>
              {zones.length === 0 ? (
                <div className="text-center py-12 text-muted-foreground">
                  <MapPin className="h-12 w-12 mx-auto mb-4 opacity-50" />
                  <p>Nenhum local de entrega cadastrado</p>
                  <Button variant="link" onClick={handleOpenCreate}>
                    Adicionar primeiro local
                  </Button>
                </div>
              ) : (
                <div className="space-y-3">
                  {zones.map((zone) => (
                    <div 
                      key={zone.id} 
                      className={`flex items-center justify-between p-4 rounded-xl border ${zone.is_active ? 'bg-card' : 'bg-muted/30 opacity-60'}`}
                    >
                      <div className="flex items-center gap-4">
                        <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center">
                          <MapPin className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                          <div className="flex items-center gap-2">
                            <p className="font-medium">{zone.name}</p>
                            {!zone.is_active && (
                              <Badge variant="secondary">Inativo</Badge>
                            )}
                          </div>
                          <div className="flex items-center gap-3 text-sm text-muted-foreground">
                            <span className="font-semibold text-foreground">
                              {formatCurrency(zone.fee)}
                            </span>
                            {zone.min_order_value && (
                              <span>• Pedido mín: {formatCurrency(zone.min_order_value)}</span>
                            )}
                          </div>
                        </div>
                      </div>

                      <div className="flex items-center gap-2">
                        <Button 
                          variant="ghost" 
                          size="icon"
                          onClick={() => updateZone.mutate({ id: zone.id, is_active: !zone.is_active })}
                        >
                          {zone.is_active ? (
                            <ToggleRight className="h-5 w-5 text-primary" />
                          ) : (
                            <ToggleLeft className="h-5 w-5" />
                          )}
                        </Button>
                        <Button 
                          variant="ghost" 
                          size="icon"
                          onClick={() => handleOpenEdit(zone)}
                        >
                          <Edit className="h-4 w-4" />
                        </Button>
                        <Button 
                          variant="ghost" 
                          size="icon"
                          onClick={() => setDeleteId(zone.id)}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        )}

        {/* Info Taxa Fixa */}
        {deliveryFeeMode === 'fixed' && (
          <Card>
            <CardContent className="py-6">
              <div className="text-center text-muted-foreground">
                <p>A taxa fixa de <strong className="text-foreground">{formatCurrency(store?.delivery_fee || 0)}</strong> está configurada nas <a href="/admin/settings" className="text-primary underline">Configurações</a>.</p>
              </div>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Dialog de Criar/Editar */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {editingZone ? 'Editar Local' : 'Novo Local de Entrega'}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="name">Nome do Bairro/CEP/Setor *</Label>
              <Input
                id="name"
                placeholder="Ex: Centro, 74000-000, Setor Bueno"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="fee">Taxa de Entrega (R$) *</Label>
                <Input
                  id="fee"
                  type="number"
                  step="0.01"
                  min="0"
                  placeholder="0,00"
                  value={formData.fee}
                  onChange={(e) => setFormData({ ...formData, fee: e.target.value })}
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="min_order">Pedido Mínimo (R$)</Label>
                <Input
                  id="min_order"
                  type="number"
                  step="0.01"
                  min="0"
                  placeholder="Opcional"
                  value={formData.min_order_value}
                  onChange={(e) => setFormData({ ...formData, min_order_value: e.target.value })}
                />
              </div>
            </div>

            <div className="flex items-center justify-between p-3 rounded-lg bg-muted/50">
              <Label htmlFor="is_active" className="cursor-pointer">
                Zona ativa
              </Label>
              <Switch
                id="is_active"
                checked={formData.is_active}
                onCheckedChange={(checked) => setFormData({ ...formData, is_active: checked })}
              />
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setIsDialogOpen(false)}>
              Cancelar
            </Button>
            <Button 
              onClick={handleSubmit}
              disabled={!formData.name.trim() || !formData.fee || createZone.isPending || updateZone.isPending}
            >
              {(createZone.isPending || updateZone.isPending) && (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              )}
              {editingZone ? 'Salvar' : 'Criar'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Dialog de Confirmação de Exclusão */}
      <AlertDialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Excluir local de entrega?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta ação não pode ser desfeita. O local será removido permanentemente.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-destructive text-destructive-foreground hover:bg-destructive/90">
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </AdminLayout>
  );
}

import { useState, useMemo } from 'react';
import { format, startOfMonth, endOfMonth, subMonths, differenceInMinutes } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { FileSpreadsheet, FileText, Loader2, TrendingUp, Clock, DollarSign, Calendar, Truck, ArrowLeft, PackageCheck } from 'lucide-react';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useDrivers } from '@/hooks/useDrivers';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface DriverDelivery {
  id: number;
  created_at: string;
  updated_at: string;
  customer_name: string;
  total_amount: number;
  payment_method: string;
  status: string;
  driver_id: string;
  driver_name: string | null;
}

const DEFAULT_COMMISSION_RATE = 0.05; // 5% commission

const AdminDriverReports = () => {
  const { toast } = useToast();
  const { data: drivers, isLoading: isLoadingDrivers } = useDrivers();
  const [selectedDriverId, setSelectedDriverId] = useState<string>('');
  const [startDate, setStartDate] = useState<Date>(startOfMonth(new Date()));
  const [endDate, setEndDate] = useState<Date>(endOfMonth(new Date()));
  const [isExporting, setIsExporting] = useState(false);

  const selectedDriver = useMemo(
    () => drivers?.find((d) => d.id === selectedDriverId),
    [drivers, selectedDriverId]
  );

  const { data: deliveries, isLoading: isLoadingDeliveries } = useQuery({
    queryKey: ['driver-report', selectedDriverId, startDate, endDate],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('orders')
        .select('*')
        .eq('driver_id', selectedDriverId)
        .gte('created_at', startDate.toISOString())
        .lte('created_at', endDate.toISOString())
        .order('created_at', { ascending: false });
      if (error) throw error;
      return (data || []) as DriverDelivery[];
    },
    enabled: !!selectedDriverId,
  });

  const isLoading = isLoadingDrivers || isLoadingDeliveries;

  const commissionRate = useMemo(() => {
    if (selectedDriver?.commission_percentage != null) {
      return selectedDriver.commission_percentage / 100;
    }
    return DEFAULT_COMMISSION_RATE;
  }, [selectedDriver]);

  const stats = useMemo(() => {
    if (!deliveries || deliveries.length === 0) {
      return { totalDeliveries: 0, avgTime: 0, totalCommission: 0, totalReceived: 0 };
    }

    const totalDeliveries = deliveries.length;
    const completed = deliveries.filter((d) => d.status === 'completed');

    const timeDiffs = completed
      .map((d) => differenceInMinutes(new Date(d.updated_at), new Date(d.created_at)))
      .filter((t) => t > 0);
    const avgTime = timeDiffs.length > 0 ? Math.round(timeDiffs.reduce((a, b) => a + b, 0) / timeDiffs.length) : 0;

    const totalReceived = completed.reduce((sum, d) => sum + d.total_amount, 0);
    const totalCommission = totalReceived * commissionRate;

    return { totalDeliveries, avgTime, totalCommission, totalReceived };
  }, [deliveries, commissionRate]);

  const formatCurrency = (value: number) =>
    value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  const formatPaymentMethod = (method: string) => {
    const methods: Record<string, string> = {
      money: 'Dinheiro', card: 'Cartão', credit: 'Crédito', debit: 'Débito', pix: 'PIX',
    };
    return methods[method] || method;
  };

  const formatStatus = (status: string) => {
    const statuses: Record<string, string> = {
      pending: 'Pendente', preparing: 'Preparando', ready: 'Pronto',
      delivery: 'Em entrega', delivered: 'Entregue', completed: 'Finalizado', cancelled: 'Cancelado',
    };
    return statuses[status] || status;
  };

  const getDeliveryTime = (d: DriverDelivery) => {
    const mins = differenceInMinutes(new Date(d.updated_at), new Date(d.created_at));
    return mins > 0 && mins < 300 ? `${mins} min` : '-';
  };

  const getCommission = (d: DriverDelivery) => d.total_amount * commissionRate;

  const setDateRange = (range: 'today' | 'week' | 'month' | 'lastMonth') => {
    const today = new Date();
    switch (range) {
      case 'today':
        setStartDate(new Date(today.getFullYear(), today.getMonth(), today.getDate()));
        setEndDate(new Date(today.getFullYear(), today.getMonth(), today.getDate(), 23, 59, 59, 999));
        break;
      case 'week': {
        const weekStart = new Date(today);
        weekStart.setDate(today.getDate() - today.getDay());
        setStartDate(new Date(weekStart.setHours(0, 0, 0, 0)));
        setEndDate(new Date(new Date().setHours(23, 59, 59, 999)));
        break;
      }
      case 'month':
        setStartDate(startOfMonth(today));
        setEndDate(endOfMonth(today));
        break;
      case 'lastMonth': {
        const lm = subMonths(today, 1);
        setStartDate(startOfMonth(lm));
        setEndDate(endOfMonth(lm));
        break;
      }
    }
  };

  const canExport = !!selectedDriverId && !!deliveries && deliveries.length > 0;

  const exportToPDF = async () => {
    if (!canExport || !selectedDriver) return;
    setIsExporting(true);
    try {
      const doc = new jsPDF();
      const now = new Date();

      // Header
      doc.setFontSize(18);
      doc.text('Relatório de Entregador', 14, 22);

      doc.setFontSize(11);
      doc.text(`Entregador: ${selectedDriver.name}`, 14, 32);
      doc.text(`Período: ${format(startDate, 'dd/MM/yyyy')} a ${format(endDate, 'dd/MM/yyyy')}`, 14, 38);
      doc.text(`Gerado em: ${format(now, "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}`, 14, 44);

      // Stats
      doc.setFontSize(10);
      doc.text(`Total de Entregas: ${stats.totalDeliveries}`, 14, 54);
      doc.text(`Tempo Médio: ${stats.avgTime} min`, 14, 60);
      doc.text(`Total de Comissões: ${formatCurrency(stats.totalCommission)}`, 14, 66);
      doc.text(`Valor Total Recebido: ${formatCurrency(stats.totalReceived)}`, 14, 72);

      // Table
      autoTable(doc, {
        startY: 80,
        head: [['Data', 'Cliente', 'Tempo de Entrega', 'Valor Comissão']],
        body: deliveries!.map((d) => [
          format(new Date(d.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }),
          d.customer_name,
          getDeliveryTime(d),
          formatCurrency(getCommission(d)),
        ]),
        styles: { fontSize: 8 },
        headStyles: { fillColor: [255, 152, 0] },
        foot: [['', '', 'TOTAL', formatCurrency(stats.totalCommission)]],
        footStyles: { fillColor: [240, 240, 240], textColor: [0, 0, 0], fontStyle: 'bold' },
        didDrawPage: (data: any) => {
          const pageCount = doc.getNumberOfPages();
          doc.setFontSize(8);
          doc.text(`Página ${data.pageNumber} de ${pageCount}`, doc.internal.pageSize.width - 30, doc.internal.pageSize.height - 10);
        },
      });

      const fileName = `relatorio-entregador-${selectedDriver.name.replace(/\s+/g, '-')}-${format(startDate, 'dd-MM-yyyy')}-a-${format(endDate, 'dd-MM-yyyy')}.pdf`;
      doc.save(fileName);
      toast({ title: 'PDF exportado!', description: fileName });
    } catch {
      toast({ title: 'Erro ao exportar PDF', variant: 'destructive' });
    } finally {
      setIsExporting(false);
    }
  };

  const exportToExcel = async () => {
    if (!canExport || !selectedDriver) return;
    setIsExporting(true);
    try {
      // Sheet 1: Summary
      const summaryData = [
        { Campo: 'Entregador', Valor: selectedDriver.name },
        { Campo: 'Período', Valor: `${format(startDate, 'dd/MM/yyyy')} a ${format(endDate, 'dd/MM/yyyy')}` },
        { Campo: 'Total de Entregas', Valor: String(stats.totalDeliveries) },
        { Campo: 'Tempo Médio', Valor: `${stats.avgTime} min` },
        { Campo: 'Total de Comissão', Valor: formatCurrency(stats.totalCommission) },
      ];
      const summarySheet = XLSX.utils.json_to_sheet(summaryData);

      // Sheet 2: Details
      const detailData = deliveries!.map((d) => ({
        Data: format(new Date(d.created_at), 'dd/MM/yyyy HH:mm', { locale: ptBR }),
        Cliente: d.customer_name,
        'Tempo de Entrega': getDeliveryTime(d),
        'Valor Comissão': formatCurrency(getCommission(d)),
        Status: formatStatus(d.status),
      }));
      const detailSheet = XLSX.utils.json_to_sheet(detailData);

      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, summarySheet, 'Resumo');
      XLSX.utils.book_append_sheet(workbook, detailSheet, 'Detalhado');

      const fileName = `relatorio-entregador-${selectedDriver.name.replace(/\s+/g, '-')}-${format(startDate, 'dd-MM-yyyy')}-a-${format(endDate, 'dd-MM-yyyy')}.xlsx`;
      XLSX.writeFile(workbook, fileName);
      toast({ title: 'Excel exportado!', description: fileName });
    } catch {
      toast({ title: 'Erro ao exportar Excel', variant: 'destructive' });
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <AdminLayout title="Relatório de Entregadores">
      <div className="space-y-6">
        {/* Driver Selector + Date Filters */}
        <div className="bg-card rounded-xl p-4 shadow-card space-y-4">
          <h3 className="font-semibold text-foreground flex items-center gap-2">
            <Truck className="h-5 w-5 text-primary" />
            Selecionar Entregador e Período
          </h3>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-sm text-muted-foreground">Entregador</label>
              <Select value={selectedDriverId} onValueChange={setSelectedDriverId}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione um entregador" />
                </SelectTrigger>
                <SelectContent>
                  {(drivers || []).map((d) => (
                    <SelectItem key={d.id} value={d.id}>{d.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="flex flex-wrap gap-2">
            <Button variant="outline" size="sm" onClick={() => setDateRange('today')}>Hoje</Button>
            <Button variant="outline" size="sm" onClick={() => setDateRange('week')}>Esta Semana</Button>
            <Button variant="outline" size="sm" onClick={() => setDateRange('month')}>Este Mês</Button>
            <Button variant="outline" size="sm" onClick={() => setDateRange('lastMonth')}>Mês Passado</Button>
          </div>

          <div className="flex flex-wrap gap-4">
            <div className="space-y-2">
              <label className="text-sm text-muted-foreground">Data Inicial</label>
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" className="w-[180px] justify-start text-left font-normal">
                    <Calendar className="mr-2 h-4 w-4" />
                    {format(startDate, 'dd/MM/yyyy', { locale: ptBR })}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <CalendarComponent mode="single" selected={startDate} onSelect={(d) => d && setStartDate(d)} initialFocus />
                </PopoverContent>
              </Popover>
            </div>
            <div className="space-y-2">
              <label className="text-sm text-muted-foreground">Data Final</label>
              <Popover>
                <PopoverTrigger asChild>
                  <Button variant="outline" className="w-[180px] justify-start text-left font-normal">
                    <Calendar className="mr-2 h-4 w-4" />
                    {format(endDate, 'dd/MM/yyyy', { locale: ptBR })}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <CalendarComponent mode="single" selected={endDate} onSelect={(d) => d && setEndDate(d)} initialFocus />
                </PopoverContent>
              </Popover>
            </div>
          </div>
        </div>

        {!selectedDriverId ? (
          <div className="text-center py-12">
            <Truck className="h-12 w-12 text-muted-foreground/50 mx-auto mb-4" />
            <p className="text-muted-foreground">Selecione um entregador para visualizar o relatório.</p>
          </div>
        ) : isLoading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        ) : !deliveries || deliveries.length === 0 ? (
          <div className="text-center py-12">
            <PackageCheck className="h-12 w-12 text-muted-foreground/50 mx-auto mb-4" />
            <p className="text-muted-foreground">Nenhuma entrega encontrada no período selecionado.</p>
          </div>
        ) : (
          <>
            {/* Stats Cards */}
            <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <PackageCheck className="h-4 w-4" /> Entregas
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-2xl font-bold text-foreground">{stats.totalDeliveries}</p>
                </CardContent>
              </Card>
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <Clock className="h-4 w-4" /> Tempo Médio
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-2xl font-bold text-foreground">{stats.avgTime} min</p>
                </CardContent>
              </Card>
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <DollarSign className="h-4 w-4" /> Comissões
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-2xl font-bold text-primary">{formatCurrency(stats.totalCommission)}</p>
                </CardContent>
              </Card>
              <Card>
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                    <TrendingUp className="h-4 w-4" /> Valor Total
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-2xl font-bold text-foreground">{formatCurrency(stats.totalReceived)}</p>
                </CardContent>
              </Card>
              <Card className="col-span-2 lg:col-span-1">
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm font-medium text-muted-foreground">Exportar</CardTitle>
                </CardHeader>
                <CardContent className="flex gap-2">
                  <Button variant="outline" size="sm" onClick={exportToPDF} disabled={isExporting} className="flex-1">
                    <FileText className="h-4 w-4 mr-1" /> PDF
                  </Button>
                  <Button variant="outline" size="sm" onClick={exportToExcel} disabled={isExporting} className="flex-1">
                    <FileSpreadsheet className="h-4 w-4 mr-1" /> Excel
                  </Button>
                </CardContent>
              </Card>
            </div>

            {/* Table */}
            <div className="bg-card rounded-xl shadow-card overflow-hidden">
              <div className="p-4 border-b border-border">
                <h3 className="font-semibold text-foreground">Entregas de {selectedDriver?.name}</h3>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-muted/50">
                    <tr>
                      <th className="text-left p-3 text-xs font-medium text-muted-foreground">Data</th>
                      <th className="text-left p-3 text-xs font-medium text-muted-foreground">Cliente</th>
                      <th className="text-left p-3 text-xs font-medium text-muted-foreground">Tempo</th>
                      <th className="text-left p-3 text-xs font-medium text-muted-foreground">Comissão</th>
                      <th className="text-left p-3 text-xs font-medium text-muted-foreground">Pagamento</th>
                      <th className="text-left p-3 text-xs font-medium text-muted-foreground">Status</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-border">
                    {deliveries.map((d) => (
                      <tr key={d.id} className="hover:bg-muted/50">
                        <td className="p-3 text-sm text-muted-foreground">
                          {format(new Date(d.created_at), 'dd/MM/yy HH:mm', { locale: ptBR })}
                        </td>
                        <td className="p-3 text-sm text-foreground">{d.customer_name}</td>
                        <td className="p-3 text-sm text-foreground">{getDeliveryTime(d)}</td>
                        <td className="p-3 text-sm font-medium text-primary">{formatCurrency(getCommission(d))}</td>
                        <td className="p-3 text-sm text-muted-foreground">{formatPaymentMethod(d.payment_method)}</td>
                        <td className="p-3">
                          <span className={cn(
                            "px-2 py-1 rounded-full text-xs font-medium",
                            d.status === 'completed' || d.status === 'delivered'
                              ? "bg-secondary/20 text-secondary"
                              : d.status === 'cancelled'
                              ? "bg-destructive/20 text-destructive"
                              : "bg-accent text-accent-foreground"
                          )}>
                            {formatStatus(d.status)}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}
      </div>
    </AdminLayout>
  );
};

