                    <span className="text-[10px] text-muted-foreground font-medium">Tipo da chave (CPF, etc)</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="flex justify-start">
            <Button type="submit" size="lg" className="min-w-[200px] shadow-lg shadow-primary/20" disabled={updateStore.isPending}>
              {updateStore.isPending ? <>
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  Salvando...
                </> : (
                  <>
                    <Send className="h-4 w-4 mr-2" />
                    Salvar Configurações
                  </>
                )}
            </Button>
          </div>
        </form>
      </div>
    </AdminLayout>
  );
};

export default AdminEnvios;

import { useState } from 'react';
import { Loader2, Clock, Plus, Pencil, Check, X, Trash2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Switch } from '@/components/ui/switch';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { useBusinessHours, useUpdateBusinessHour, useCreateBusinessHours, useDeleteBusinessHour, getDayName, BusinessHour } from '@/hooks/useBusinessHours';
import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import { supabase } from '@/integrations/supabase/client';
import { useQueryClient } from '@tanstack/react-query';

const AdminHours = () => {
  const { data: hours, isLoading } = useBusinessHours();
  const updateHour = useUpdateBusinessHour();
  const createHours = useCreateBusinessHours();
  const deleteHour = useDeleteBusinessHour();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [editingId, setEditingId] = useState<string | null>(null);
  const [editData, setEditData] = useState({
    open_time: '',
    close_time: '',
  });

  const handleEdit = (hour: BusinessHour) => {
    setEditingId(hour.id);
    setEditData({
      open_time: hour.open_time,
      close_time: hour.close_time,
    });
  };

  const handleSave = async (hour: BusinessHour) => {
    try {
      await updateHour.mutateAsync({
        id: hour.id,
        open_time: editData.open_time,
        close_time: editData.close_time,
      });
      setEditingId(null);
      toast({ title: 'Horário atualizado!' });
    } catch (error: any) {
      toast({ title: 'Erro ao salvar', description: error.message, variant: 'destructive' });
    }
  };

  const toggleActive = async (hour: BusinessHour) => {
    try {
      await updateHour.mutateAsync({
        id: hour.id,
        is_active: !hour.is_active,
      });
      toast({ title: hour.is_active ? 'Horário desativado' : 'Horário ativado' });
    } catch (error) {
      toast({ title: 'Erro ao atualizar', variant: 'destructive' });
    }
  };

  const handleCreateHours = async () => {
    try {
      await createHours.mutateAsync();
      toast({ title: 'Horários criados com sucesso!' });
    } catch (error: any) {
      toast({ title: 'Erro ao criar horários', description: error.message, variant: 'destructive' });
    }
  };

  const handleAddSlot = async (dayOfWeek: number) => {
    try {
      const { error } = await supabase
        .from('business_hours')
        .insert({
          day_of_week: dayOfWeek,
          open_time: '12:00',
          close_time: '14:00',
          is_active: true,
        });
      if (error) throw error;
      queryClient.invalidateQueries({ queryKey: ['business-hours'] });
      toast({ title: 'Horário adicionado!' });
    } catch (error: any) {
      toast({ title: 'Erro ao adicionar', description: error.message, variant: 'destructive' });
    }
  };

  const handleDeleteSlot = async (id: string) => {
    try {
      await deleteHour.mutateAsync(id);
      toast({ title: 'Horário removido!' });
    } catch (error: any) {
      toast({ title: 'Erro ao remover', description: error.message, variant: 'destructive' });
    }
  };

  if (isLoading) {
    return (
      <AdminLayout title="Horários">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      </AdminLayout>
    );
  }

  if (!hours || hours.length === 0) {
    return (
      <AdminLayout title="Horários de Funcionamento">
        <div className="w-full max-w-2xl">
          <div className="flex items-center gap-3 mb-4 sm:mb-6 p-3 sm:p-4 bg-primary/10 rounded-xl">
            <Clock className="h-5 w-5 sm:h-6 sm:w-6 text-primary shrink-0" />
            <div className="min-w-0">
              <p className="font-medium text-foreground text-sm sm:text-base">Configure os horários de funcionamento</p>
              <p className="text-xs sm:text-sm text-muted-foreground">
                Defina quando sua loja está aberta para receber pedidos
              </p>
            </div>
          </div>

          <div className="bg-card rounded-xl shadow-card p-6 sm:p-8 text-center">
            <Clock className="h-10 w-10 sm:h-12 sm:w-12 text-muted-foreground mx-auto mb-4" />
            <h3 className="text-base sm:text-lg font-medium text-foreground mb-2">Nenhum horário cadastrado</h3>
            <p className="text-sm text-muted-foreground mb-6">
              Clique no botão abaixo para criar os horários de funcionamento para todos os dias da semana.
            </p>
            <Button onClick={handleCreateHours} disabled={createHours.isPending}>
              {createHours.isPending ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : (
                <Plus className="h-4 w-4 mr-2" />
              )}
              Criar Horários
            </Button>
          </div>
        </div>
      </AdminLayout>
    );
  }

  // Group hours by day_of_week
  const hoursByDay: Record<number, BusinessHour[]> = {};
  for (let d = 0; d < 7; d++) {
    hoursByDay[d] = hours.filter(h => h.day_of_week === d);
  }

  return (
    <AdminLayout title="Horários de Funcionamento">
      <div className="w-full max-w-2xl">
        <div className="flex items-center gap-3 mb-4 sm:mb-6 p-3 sm:p-4 bg-primary/10 rounded-xl">
          <Clock className="h-5 w-5 sm:h-6 sm:w-6 text-primary shrink-0" />
          <div className="min-w-0">
            <p className="font-medium text-foreground text-sm sm:text-base">Configure os horários de funcionamento</p>
            <p className="text-xs sm:text-sm text-muted-foreground">
              Defina quando sua loja está aberta. Adicione múltiplos horários por dia.
            </p>
          </div>
        </div>

        <div className="bg-card rounded-xl shadow-card overflow-hidden">
          {[0, 1, 2, 3, 4, 5, 6].map((day) => {
            const daySlots = hoursByDay[day] || [];
            const hasSlots = daySlots.length > 0;

            return (
              <div key={day} className="border-b border-border last:border-0 p-3 sm:p-4">
                {/* Day header */}
                <div className="flex items-center justify-between mb-2">
                  <p className="font-semibold text-foreground text-sm sm:text-base">
                    {getDayName(day)}
                  </p>
                  {!hasSlots && (
                    <span className="text-xs text-muted-foreground">Sem horários</span>
                  )}
                </div>

                {/* Time slots */}
                <div className="space-y-2">
                  {daySlots.map((hour, idx) => (
                    <div
                      key={hour.id}
                      className={cn(
                        "flex items-center gap-2 sm:gap-3 pl-2",
                        !hour.is_active && "opacity-50"
                      )}
                    >
                      <Switch
                        checked={hour.is_active}
                        onCheckedChange={() => toggleActive(hour)}
                        className="shrink-0"
                      />

                      {editingId === hour.id ? (
                        <div className="flex items-center gap-2 flex-1">
                          <Input
                            type="time"
                            value={editData.open_time}
                            onChange={(e) => setEditData({ ...editData, open_time: e.target.value })}
                            className="w-full sm:w-28"
                          />
                          <span className="text-muted-foreground text-sm shrink-0">às</span>
                          <Input
                            type="time"
                            value={editData.close_time}
                            onChange={(e) => setEditData({ ...editData, close_time: e.target.value })}
                            className="w-full sm:w-28"
                          />
                          <Button
                            size="icon"
                            variant="ghost"
                            className="h-8 w-8 text-primary shrink-0"
                            onClick={() => handleSave(hour)}
                            disabled={updateHour.isPending}
                          >
                            {updateHour.isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4" />}
                          </Button>
                          <Button
                            size="icon"
                            variant="ghost"
                            className="h-8 w-8 shrink-0"
                            onClick={() => setEditingId(null)}
                          >
                            <X className="h-4 w-4" />
                          </Button>
                        </div>
                      ) : (
                        <div className="flex items-center justify-between flex-1">
                          <p className={cn(
                            "text-sm",
                            hour.is_active ? "text-foreground" : "text-muted-foreground"
                          )}>
                            {hour.open_time.slice(0, 5)} às {hour.close_time.slice(0, 5)}
                          </p>
                          <div className="flex items-center gap-1">
                            <Button
                              size="icon"
                              variant="ghost"
                              className="h-7 w-7"
                              onClick={() => handleEdit(hour)}
                            >
                              <Pencil className="h-3.5 w-3.5" />
                            </Button>
                            {daySlots.length > 1 && (
                              <Button
                                size="icon"
                                variant="ghost"
                                className="h-7 w-7 text-destructive hover:text-destructive"
                                onClick={() => handleDeleteSlot(hour.id)}
                              >
                                <Trash2 className="h-3.5 w-3.5" />
                              </Button>
                            )}
                          </div>
                        </div>
                      )}
                    </div>
                  ))}
                </div>

                {/* Add slot button */}
                <button
                  onClick={() => handleAddSlot(day)}
                  className="mt-2 flex items-center gap-1.5 text-xs text-primary hover:text-primary/80 transition-colors pl-2"
                >
                  <Plus className="h-3.5 w-3.5" />
                  Adicionar horário
                </button>
              </div>
            );
          })}
        </div>

        <p className="text-xs text-muted-foreground mt-4 text-center">
          Adicione múltiplos horários por dia (ex: almoço e jantar)
        </p>
      </div>
    </AdminLayout>
  );
};

export default AdminHours;

import { useState } from 'react';
import { Plus, Pencil, Trash2, Loader2, Search, Package, Settings, AlertTriangle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { useIngredients, useCreateIngredient, useUpdateIngredient, useDeleteIngredient, Ingredient } from '@/hooks/useIngredients';
import { useSystemSettings, useUpdateSystemSettings } from '@/hooks/useSystemSettings';
import { useToast } from '@/hooks/use-toast';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
const AdminIngredients = () => {
  const { data: ingredients, isLoading } = useIngredients();
  const createIngredient = useCreateIngredient();
  const updateIngredient = useUpdateIngredient();
  const deleteIngredient = useDeleteIngredient();
  const { toast } = useToast();

  const { data: systemSettings, isLoading: isLoadingSettings } = useSystemSettings();
  const updateSettings = useUpdateSystemSettings();

  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingIngredient, setEditingIngredient] = useState<Ingredient | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    stock_quantity: '',
    unit: 'un',
    min_stock: '',
  });

  const filteredIngredients = ingredients?.filter(ing => 
    ing.name.toLowerCase().includes(search.toLowerCase())
  ) || [];

  const criticalIngredients = ingredients?.filter(ing => 
    ing.stock_quantity <= ing.min_stock
  ) || [];

  const openCreateModal = () => {
    setEditingIngredient(null);
    setFormData({
      name: '',
      stock_quantity: '0',
      unit: 'un',
      min_stock: '0',
    });
    setIsModalOpen(true);
  };

  const openEditModal = (ingredient: Ingredient) => {
    setEditingIngredient(ingredient);
    setFormData({
      name: ingredient.name,
      stock_quantity: ingredient.stock_quantity.toString(),
      unit: ingredient.unit,
      min_stock: ingredient.min_stock.toString(),
    });
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name.trim()) {
      toast({ title: 'Nome é obrigatório', variant: 'destructive' });
      return;
    }

    const stock_quantity = parseFloat(formData.stock_quantity.replace(',', '.'));
    const min_stock = parseFloat(formData.min_stock.replace(',', '.'));

    try {
      const data = {
        name: formData.name,
        stock_quantity: isNaN(stock_quantity) ? 0 : stock_quantity,
        unit: formData.unit,
        min_stock: isNaN(min_stock) ? 0 : min_stock,
      };

      if (editingIngredient) {
        await updateIngredient.mutateAsync({ id: editingIngredient.id, ...data });
        toast({ title: 'Item atualizado!' });
      } else {
        await createIngredient.mutateAsync(data);
        toast({ title: 'Item criado!' });
      }

      setIsModalOpen(false);
    } catch (error: any) {
      toast({ title: 'Erro ao salvar', description: error.message, variant: 'destructive' });
    }
  };

  const handleDelete = async (ingredient: Ingredient) => {
    if (!confirm(`Deseja excluir "${ingredient.name}"? Isso pode afetar produtos que usam este item.`)) return;

    try {
      await deleteIngredient.mutateAsync(ingredient.id);
      toast({ title: 'Item excluído!' });
    } catch (error: any) {
      toast({ title: 'Erro ao excluir', description: error.message, variant: 'destructive' });
    }
  };

  if (isLoading) {
    return (
      <AdminLayout title="Estoque">
        <div className="flex items-center justify-center h-64">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      </AdminLayout>
    );
  }

  return (
    <AdminLayout title="Estoque">
      {/* Settings Section */}
      <div className="bg-card rounded-xl p-4 shadow-card mb-6 border border-border">
        <h2 className="text-lg font-semibold mb-4 text-foreground flex items-center gap-2">
          <Settings className="h-5 w-5 text-primary" />
          Configurações de Estoque
        </h2>

        {isLoadingSettings ? (
          <div className="flex justify-center p-4">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
          </div>
        ) : (
          <div className="flex flex-col gap-4 sm:flex-row sm:gap-8">
            <div className="flex items-center space-x-2">
              <Switch 
                id="stock-enabled" 
                checked={systemSettings?.stock_enabled ?? true}
                onCheckedChange={(checked) => updateSettings.mutateAsync({ stock_enabled: checked })}
                className="data-[state=checked]:bg-[#23354D]"
              />
              <Label htmlFor="stock-enabled" className="cursor-pointer font-medium">
                Ativar Controle de Estoque
              </Label>
            </div>

            <div className={`flex items-center space-x-2 transition-opacity ${!systemSettings?.stock_enabled ? 'opacity-50 pointer-events-none' : ''}`}>
              <Switch 
                id="product-stock-enabled" 
                checked={systemSettings?.product_stock_enabled ?? true}
                onCheckedChange={(checked) => updateSettings.mutateAsync({ product_stock_enabled: checked })}
                disabled={!systemSettings?.stock_enabled}
                className="data-[state=checked]:bg-[#23354D]"
              />
              <Label htmlFor="product-stock-enabled" className="cursor-pointer font-medium">
                Ativar Estoque por Produto
              </Label>
            </div>
          </div>
        )}
      </div>

      {/* Header */}
      <div className="flex flex-col sm:flex-row gap-3 sm:gap-4 mb-4 sm:mb-6">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input 
            placeholder="Buscar estoque..." 
            className="pl-9 h-11 bg-card border-border shadow-sm rounded-xl focus-visible:ring-primary"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            disabled={!systemSettings?.stock_enabled}
          />
        </div>

        {systemSettings?.stock_enabled && (
          <Button 
            onClick={openCreateModal}
            className="h-11 shadow-sm rounded-xl font-medium sm:w-auto w-full gap-2 text-primary-foreground transition-all hover:scale-[1.02] active:scale-[0.98]"
          >
            <Plus className="h-5 w-5" /> Novo Item de Estoque
          </Button>
        )}
      </div>

      {!systemSettings?.stock_enabled ? (
        <div className="text-center p-12 bg-card rounded-xl border border-border shadow-sm">
          <Package className="h-16 w-16 text-muted-foreground/30 mx-auto mb-4" />
          <h3 className="text-xl font-semibold text-foreground mb-2">Estoque Global Desativado</h3>
          <p className="text-muted-foreground max-w-md mx-auto">
            O gerenciamento de estoque foi totalmente desativado nas configurações. 
            Ative-o no painel acima para gerenciar os seus itens e movimentações de estoque.
          </p>
        </div>
      ) : (
        <>
          {criticalIngredients.length > 0 && (
            <div className="mb-6 space-y-2">
              {criticalIngredients.map(ing => (
                <div key={`critical-${ing.id}`} className="bg-destructive/10 border-l-4 border-destructive p-3 rounded-r-lg flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
                  <AlertTriangle className="h-5 w-5 text-destructive shrink-0" />
                  <div>
                    <h4 className="font-semibold text-destructive text-sm leading-none">⚠️ Estoque no mínimo</h4>
                    <p className="text-sm text-destructive/90 mt-1">
                      O ingrediente <span className="font-bold">{ing.name}</span> atingiu o estoque mínimo. Quantidade atual: {ing.stock_quantity} {ing.unit}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          )}

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 sm:gap-4">
            {filteredIngredients.map((ingredient) => {
              const isCritical = ingredient.stock_quantity <= ingredient.min_stock;
              return (
                <div 
                  key={ingredient.id} 
                  className={`bg-card rounded-xl p-4 shadow-card border-2 transition-colors ${
                    isCritical ? 'border-destructive/40 bg-destructive/5' : 'border-transparent'
                  }`}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex items-center gap-3">
                      <div className={`h-10 w-10 rounded-lg flex items-center justify-center ${
                        isCritical ? 'bg-destructive/10 text-destructive' : 'bg-primary/10 text-primary'
                      }`}>
                        {isCritical ? <AlertTriangle className="h-5 w-5" /> : <Package className="h-5 w-5" />}
                      </div>
                      <div>
                        <h3 className="font-semibold text-foreground">{ingredient.name}</h3>
                        <p className="text-xs text-muted-foreground">
                          Estoque: <span className={isCritical ? "text-destructive font-bold" : ""}>
                            {ingredient.stock_quantity} {ingredient.unit}
                          </span>
                        </p>
                      </div>
                    </div>
                    <div className="flex gap-1">
                      <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => openEditModal(ingredient)}>
                        <Pencil className="h-4 w-4" />
                      </Button>
                      <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => handleDelete(ingredient)}>
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                </div>
              );
            })}

            {filteredIngredients.length === 0 && (
              <div className="col-span-full py-12 text-center text-muted-foreground">
                Nenhum item de estoque encontrado
              </div>
            )}
          </div>
        </>
      )}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>
              {editingIngredient ? 'Editar Item' : 'Novo Item'}
            </DialogTitle>
          </DialogHeader>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="text-sm text-muted-foreground">Nome *</label>
              <Input
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                placeholder="Ex: Carne moída, Pão de hambúrguer"
                className="mt-1"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm text-muted-foreground">Qtd em Estoque</label>
                <Input
                  value={formData.stock_quantity}
                  onChange={(e) => setFormData({ ...formData, stock_quantity: e.target.value })}
                  placeholder="0.000"
                  className="mt-1"
                />
              </div>
              <div>
                <label className="text-sm text-muted-foreground">Unidade</label>
                <select
                  className="w-full mt-1 h-10 rounded-md border border-input bg-background px-3 py-2 text-sm"
                  value={formData.unit}
                  onChange={(e) => setFormData({ ...formData, unit: e.target.value })}
                >
                  <option value="un">un (unidade)</option>
                  <option value="kg">kg (quilo)</option>
                  <option value="g">g (grama)</option>
                  <option value="L">l (litro)</option>
                  <option value="ml">ml (mililitro)</option>
                </select>
              </div>
            </div>

            <div>
              <label className="text-sm text-muted-foreground">Estoque Mínimo</label>
              <Input
                value={formData.min_stock}
                onChange={(e) => setFormData({ ...formData, min_stock: e.target.value })}
                placeholder="0.000"
                className="mt-1"
              />
            </div>

            <div className="flex justify-end gap-2 pt-4">
              <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)}>
                Cancelar
              </Button>
              <Button type="submit" disabled={createIngredient.isPending || updateIngredient.isPending}>
                {editingIngredient ? 'Salvar' : 'Criar'}
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </AdminLayout>
  );
};

export default AdminIngredients;

