export default AdminSettings;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Loader2, Store, Phone, CreditCard, Truck, ChevronRight, Check, Sparkles, ArrowLeft } from 'lucide-react';
import { Helmet } from 'react-helmet-async';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { ImageUpload } from '@/components/admin/ImageUpload';
import { useStoreConfig, useUpdateStoreConfig } from '@/hooks/useStore';
import { useToast } from '@/hooks/use-toast';

const steps = [
  { id: 'info', title: 'Informações', icon: Store },
  { id: 'contact', title: 'Contato', icon: Phone },
  { id: 'payment', title: 'Pagamento', icon: CreditCard },
  { id: 'delivery', title: 'Entrega', icon: Truck },
];

const AdminSetup = () => {
  const navigate = useNavigate();
  const { toast } = useToast();
  const { data: store, isLoading } = useStoreConfig();
  const updateStore = useUpdateStoreConfig();
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    name: '',
    logo_url: '',
    cover_url: '',
    address: '',
    phone_whatsapp: '',
    pix_key_type: 'Telefone',
    pix_key: '',
    delivery_fee: '5',
    delivery_time_min: '30',
    delivery_time_max: '45',
  });

  // Pre-populate form with existing data
  useEffect(() => {
    if (store) {
      setFormData({
        name: store.name || '',
        logo_url: store.logo_url || '',
        cover_url: store.cover_url || '',
        address: store.address || '',
        phone_whatsapp: store.phone_whatsapp || '',
        pix_key_type: store.pix_key_type || 'Telefone',
        pix_key: store.pix_key || '',
        delivery_fee: store.delivery_fee?.toString() || '5',
        delivery_time_min: store.delivery_time_min?.toString() || '30',
        delivery_time_max: store.delivery_time_max?.toString() || '45',
      });
    }
  }, [store]);

  const handleNavigateBack = () => {
    navigate('/admin');
  };

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      handleComplete();
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    } else {
      handleNavigateBack();
    }
  };

  const handleComplete = async () => {
    if (!store?.id) return;

    if (!formData.name.trim()) {
      toast({
        title: 'Nome obrigatório',
        description: 'Por favor, informe o nome do seu restaurante',
        variant: 'destructive',
      });
      setCurrentStep(0);
      return;
    }

    try {
      await updateStore.mutateAsync({
        id: store.id,
        name: formData.name.trim(),
        logo_url: formData.logo_url || null,
        cover_url: formData.cover_url || null,
        address: formData.address || null,
        phone_whatsapp: formData.phone_whatsapp || null,
        pix_key_type: formData.pix_key_type,
        pix_key: formData.pix_key || null,
        delivery_fee: parseFloat(formData.delivery_fee.replace(',', '.')) || 5,
        delivery_time_min: parseInt(formData.delivery_time_min) || 30,
        delivery_time_max: parseInt(formData.delivery_time_max) || 45,
      });

      toast({
        title: '🎉 Configuração concluída!',
        description: 'Seu restaurante está pronto para receber pedidos.',
      });

      navigate('/admin');
    } catch (error: any) {
      toast({
        title: 'Erro ao salvar',
        description: error.message,
        variant: 'destructive',
      });
    }
  };


  const renderStepContent = () => {
    switch (currentStep) {
      case 0:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">Nome do Restaurante *</label>
              <Input
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                placeholder="Ex: Pizzaria do João"
                className="mt-1"
                autoFocus
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Logo</label>
              <ImageUpload
                bucket="store-assets"
                currentUrl={formData.logo_url}
                onUpload={(url) => setFormData({ ...formData, logo_url: url })}
                onRemove={() => setFormData({ ...formData, logo_url: '' })}
                className="mt-1"
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Imagem de Capa</label>
              <ImageUpload
                bucket="store-assets"
                currentUrl={formData.cover_url}
                onUpload={(url) => setFormData({ ...formData, cover_url: url })}
                onRemove={() => setFormData({ ...formData, cover_url: '' })}
                className="mt-1"
              />
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Endereço</label>
              <Input
                value={formData.address}
                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                placeholder="Rua, número, bairro, cidade"
                className="mt-1"
              />
            </div>
          </div>
        );

      case 1:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">WhatsApp</label>
              <Input
                value={formData.phone_whatsapp}
                onChange={(e) => setFormData({ ...formData, phone_whatsapp: e.target.value })}
                placeholder="11999999999"
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">
                Apenas números, com DDD. Os clientes usarão para contato.
              </p>
            </div>
          </div>
        );

      case 2:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">Tipo da Chave PIX</label>
              <Select
                value={formData.pix_key_type}
                onValueChange={(value) => setFormData({ ...formData, pix_key_type: value })}
              >
                <SelectTrigger className="mt-1">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Telefone">Telefone</SelectItem>
                  <SelectItem value="CPF">CPF</SelectItem>
                  <SelectItem value="CNPJ">CNPJ</SelectItem>
                  <SelectItem value="Email">Email</SelectItem>
                  <SelectItem value="Aleatória">Aleatória</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <label className="text-sm font-medium text-foreground">Chave PIX</label>
              <Input
                value={formData.pix_key}
                onChange={(e) => setFormData({ ...formData, pix_key: e.target.value })}
                placeholder="Sua chave PIX"
                className="mt-1"
              />
            </div>
          </div>
        );

      case 3:
        return (
          <div className="space-y-4">
            <div>
              <label className="text-sm font-medium text-foreground">Taxa de Entrega (R$)</label>
              <Input
                value={formData.delivery_fee}
                onChange={(e) => setFormData({ ...formData, delivery_fee: e.target.value })}
                placeholder="5,00"
                className="mt-1"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium text-foreground">Tempo Mínimo (min)</label>
                <Input
                  value={formData.delivery_time_min}
                  onChange={(e) => setFormData({ ...formData, delivery_time_min: e.target.value })}
                  placeholder="30"
                  className="mt-1"
                  type="number"
                />
              </div>
              <div>
                <label className="text-sm font-medium text-foreground">Tempo Máximo (min)</label>
                <Input
                  value={formData.delivery_time_max}
                  onChange={(e) => setFormData({ ...formData, delivery_time_max: e.target.value })}
                  placeholder="45"
                  className="mt-1"
                  type="number"
                />
              </div>
            </div>
            <p className="text-xs text-muted-foreground">
              Tempo estimado de entrega que aparecerá para os clientes.
            </p>
          </div>
        );

      default:
        return null;
    }
  };

  if (isLoading) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <>
      <Helmet>
        <title>Configurar Restaurante - {store?.name || 'Admin'}</title>
      </Helmet>

      <div className="min-h-screen bg-background">
        {/* Header */}
        <header className="sticky top-0 z-40 flex items-center gap-3 bg-background px-4 py-4 border-b border-border">
          <Button 
            variant="ghost" 
            size="icon" 
            onClick={handleNavigateBack}
            type="button"
          >
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center">
              <Sparkles className="h-4 w-4 text-primary" />
            </div>
            <div>
              <h1 className="text-lg font-bold text-foreground">Configure seu Restaurante</h1>
              <p className="text-xs text-muted-foreground">Vamos configurar as informações básicas</p>
            </div>
          </div>
        </header>

        <div className="max-w-lg mx-auto p-4 space-y-6">
          {/* Steps indicator */}
          <div className="flex justify-between overflow-x-auto pb-2">
            {steps.map((step, index) => {
              const Icon = step.icon;
              const isActive = index === currentStep;
              const isCompleted = index < currentStep;

              return (
                <button
                  key={step.id}
                  type="button"
                  onClick={() => setCurrentStep(index)}
                  className={`flex flex-col items-center gap-1 transition-colors min-w-[60px] ${
                    isActive ? 'text-primary' : isCompleted ? 'text-secondary' : 'text-muted-foreground'
                  }`}
                >
                  <div
                    className={`h-9 w-9 rounded-full flex items-center justify-center transition-colors ${
                      isActive
                        ? 'bg-primary text-primary-foreground'
                        : isCompleted
                        ? 'bg-secondary text-secondary-foreground'
                        : 'bg-muted'
                    }`}
                  >
                    {isCompleted ? <Check className="h-4 w-4" /> : <Icon className="h-4 w-4" />}
                  </div>
                  <span className="text-[10px] font-medium">{step.title}</span>
                </button>
              );
            })}
          </div>

          {/* Step content */}
          <div className="bg-card rounded-xl p-6 shadow-card min-h-[300px]">
            {renderStepContent()}
          </div>

          {/* Navigation */}
          <div className="flex justify-between gap-4">
            <Button
              variant="outline"
              onClick={handleBack}
              className="flex-1"
              type="button"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              Voltar
            </Button>
            <Button 
              onClick={handleNext} 
              disabled={updateStore.isPending}
              className="flex-1"
              type="button"
            >
              {updateStore.isPending ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  Salvando...
                </>
              ) : currentStep === steps.length - 1 ? (
                <>
                  Concluir
                  <Check className="h-4 w-4 ml-2" />
                </>
              ) : (
                <>
                  Próximo
                  <ChevronRight className="h-4 w-4 ml-2" />
                </>
              )}
            </Button>
          </div>
        </div>
      </div>
    </>
  );
};

export default AdminSetup;

import { useState } from 'react';
import { AdminLayout } from '@/components/admin/AdminLayout';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { useToast } from '@/hooks/use-toast';
import {
  useAdminUsers, useCreateAdminUser, useUpdateAdminUser, useDeleteAdminUser,
  AdminUser, PERM_KEYS, PERM_LABELS, PermKey, PermMap,
} from '@/hooks/useAdminUsers';
import { Plus, Pencil, Trash2, Key, Loader2, Users as UsersIcon } from 'lucide-react';

const defaultPerms = (): PermMap =>
  Object.fromEntries(PERM_KEYS.map(k => [k, false])) as PermMap;

export default function Users() {
  const { toast } = useToast();
  const { data: users, isLoading } = useAdminUsers();
  const createUser = useCreateAdminUser();
  const updateUser = useUpdateAdminUser();
  const deleteUser = useDeleteAdminUser();

  const [showForm, setShowForm] = useState(false);
  const [editingUser, setEditingUser] = useState<AdminUser | null>(null);
  const [showPasswordDialog, setShowPasswordDialog] = useState<string | null>(null);

  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [confirmarSenha, setConfirmarSenha] = useState('');
  const [permissions, setPermissions] = useState<PermMap>(defaultPerms());

  const [novaSenha, setNovaSenha] = useState('');
  const [confirmarNovaSenha, setConfirmarNovaSenha] = useState('');

  const resetForm = () => {
    setUsuario('');
    setSenha('');
    setConfirmarSenha('');
    setPermissions(defaultPerms());
    setEditingUser(null);
    setShowForm(false);
  };

  const openEdit = (user: AdminUser) => {
    setEditingUser(user);
    setUsuario(user.usuario);
    const perms = {} as PermMap;
    PERM_KEYS.forEach(k => { perms[k] = user[k]; });
    setPermissions(perms);
    setSenha('');
    setConfirmarSenha('');
    setShowForm(true);
  };

  const togglePerm = (key: PermKey) => {
    setPermissions(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const selectAll = () => {
    setPermissions(Object.fromEntries(PERM_KEYS.map(k => [k, true])) as PermMap);
  };

  const deselectAll = () => {
    setPermissions(defaultPerms());
  };

  const handleSubmit = async () => {
    if (!usuario.trim()) {
      toast({ title: 'Erro', description: 'Informe o nome de usuário.', variant: 'destructive' });
      return;
    }

    if (!editingUser) {
      if (!senha || senha.length < 4) {
        toast({ title: 'Erro', description: 'Senha deve ter pelo menos 4 caracteres.', variant: 'destructive' });
        return;
      }
      if (senha !== confirmarSenha) {
        toast({ title: 'Erro', description: 'As senhas não coincidem.', variant: 'destructive' });
        return;
      }
      try {
        await createUser.mutateAsync({
          usuario: usuario.trim(),
          senha,
          permissions,
        });
        toast({ title: 'Sucesso', description: 'Usuário criado com sucesso.' });
        resetForm();
      } catch (e: any) {
        toast({ title: 'Erro', description: e.message || 'Erro ao criar usuário.', variant: 'destructive' });
      }
    } else {
      try {
        await updateUser.mutateAsync({
          id: editingUser.id,
          usuario: usuario.trim(),
          permissions,
        });
        toast({ title: 'Sucesso', description: 'Usuário atualizado.' });
        resetForm();
      } catch (e: any) {
        toast({ title: 'Erro', description: e.message || 'Erro ao atualizar.', variant: 'destructive' });
      }
    }
  };

  const handleChangePassword = async () => {
    if (!novaSenha || novaSenha.length < 4) {
      toast({ title: 'Erro', description: 'Senha deve ter pelo menos 4 caracteres.', variant: 'destructive' });
      return;
    }
    if (novaSenha !== confirmarNovaSenha) {
      toast({ title: 'Erro', description: 'As senhas não coincidem.', variant: 'destructive' });
      return;
    }
    try {
      await updateUser.mutateAsync({ id: showPasswordDialog!, senha: novaSenha });
      toast({ title: 'Sucesso', description: 'Senha alterada.' });
      setShowPasswordDialog(null);
      setNovaSenha('');
      setConfirmarNovaSenha('');
    } catch (e: any) {
      toast({ title: 'Erro', description: e.message, variant: 'destructive' });
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Tem certeza que deseja excluir este usuário?')) return;
    try {
      await deleteUser.mutateAsync(id);
      toast({ title: 'Sucesso', description: 'Usuário excluído.' });
    } catch (e: any) {
      toast({ title: 'Erro', description: e.message, variant: 'destructive' });
    }
  };

  const PermissionBadges = ({ user }: { user: AdminUser }) => {
    const activePerms = PERM_KEYS.filter(k => user[k]);
    if (activePerms.length === 0) {
      return <Badge variant="outline" className="text-xs text-muted-foreground">Sem permissões</Badge>;
    }
    if (activePerms.length === PERM_KEYS.length) {
      return <Badge variant="secondary" className="text-xs">Acesso total</Badge>;
    }
    return (
      <div className="flex flex-wrap gap-1">
        {activePerms.map(k => (
          <Badge key={k} variant="secondary" className="text-xs">{PERM_LABELS[k]}</Badge>
        ))}
      </div>
    );
  };

  return (
    <AdminLayout title="Usuários">
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <UsersIcon className="h-5 w-5 text-primary" />
            <h2 className="text-lg font-semibold text-foreground">Gerenciamento de Usuários</h2>
          </div>
          <Button onClick={() => { resetForm(); setShowForm(true); }} size="sm">
            <Plus className="h-4 w-4 mr-1" /> Novo Usuário
          </Button>
        </div>

        {showForm && (
          <Card className="admin-card">
            <CardHeader>
              <CardTitle className="text-base">
                {editingUser ? 'Editar Usuário' : 'Novo Usuário'}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Usuário</Label>
                  <Input value={usuario} onChange={e => setUsuario(e.target.value)} placeholder="Nome de login" />
                </div>
                {!editingUser && (
                  <>
                    <div className="space-y-2">
                      <Label>Senha</Label>
                      <Input type="password" value={senha} onChange={e => setSenha(e.target.value)} placeholder="Senha" />
                    </div>
                    <div className="space-y-2">
                      <Label>Confirmar Senha</Label>
                      <Input type="password" value={confirmarSenha} onChange={e => setConfirmarSenha(e.target.value)} placeholder="Confirmar senha" />
                    </div>
                  </>
                )}
              </div>

              {/* Per-menu permissions */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <Label className="text-sm font-semibold">Permissões de acesso</Label>
                  <div className="flex gap-2">
                    <Button variant="outline" size="sm" type="button" onClick={selectAll}>Selecionar todos</Button>
                    <Button variant="outline" size="sm" type="button" onClick={deselectAll}>Desmarcar todos</Button>
                  </div>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2">
                  {PERM_KEYS.map(key => (
                    <label
                      key={key}
                      className="flex items-center gap-2 rounded-lg border p-3 cursor-pointer hover:bg-accent/50 transition-colors"
                    >
                      <Checkbox
                        checked={permissions[key]}
                        onCheckedChange={() => togglePerm(key)}
                      />
                      <span className="text-sm font-medium">{PERM_LABELS[key]}</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="flex gap-2">
                <Button onClick={handleSubmit} disabled={createUser.isPending || updateUser.isPending}>
                  {(createUser.isPending || updateUser.isPending) && <Loader2 className="h-4 w-4 mr-1 animate-spin" />}
                  {editingUser ? 'Salvar' : 'Criar Usuário'}
                </Button>
                <Button variant="outline" onClick={resetForm}>Cancelar</Button>
              </div>
            </CardContent>
          </Card>
        )}

        {isLoading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
          </div>
        ) : !users?.length ? (
          <Card className="admin-card">
            <CardContent className="py-8 text-center text-muted-foreground">
              Nenhum usuário cadastrado.
            </CardContent>
          </Card>
        ) : (
          <div className="space-y-2">
            {users.map(user => (
              <Card key={user.id} className="admin-card">
                <CardContent className="flex items-center justify-between py-3 px-4">
                  <div className="space-y-1">
                    <p className="font-medium text-sm">{user.usuario}</p>
                    {user.login_email && (
                      <p className="text-xs text-muted-foreground">Login: {user.login_email}</p>
                    )}
                    <PermissionBadges user={user} />
                  </div>
                  <div className="flex gap-1">
                    <Button variant="ghost" size="icon" onClick={() => openEdit(user)} title="Editar">
                      <Pencil className="h-4 w-4" />
                    </Button>
                    <Button variant="ghost" size="icon" onClick={() => { setShowPasswordDialog(user.id); setNovaSenha(''); setConfirmarNovaSenha(''); }} title="Alterar senha">
                      <Key className="h-4 w-4" />
                    </Button>
                    <Button variant="ghost" size="icon" onClick={() => handleDelete(user.id)} title="Excluir" className="text-destructive hover:text-destructive">
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      <Dialog open={!!showPasswordDialog} onOpenChange={() => setShowPasswordDialog(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Alterar Senha</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <div className="space-y-2">
              <Label>Nova Senha</Label>
              <Input type="password" value={novaSenha} onChange={e => setNovaSenha(e.target.value)} placeholder="Nova senha" />
            </div>
            <div className="space-y-2">
              <Label>Confirmar Nova Senha</Label>
              <Input type="password" value={confirmarNovaSenha} onChange={e => setConfirmarNovaSenha(e.target.value)} placeholder="Confirmar nova senha" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowPasswordDialog(null)}>Cancelar</Button>
            <Button onClick={handleChangePassword} disabled={updateUser.isPending}>
              {updateUser.isPending && <Loader2 className="h-4 w-4 mr-1 animate-spin" />}
              Alterar Senha
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </AdminLayout>
  );
}

import jsPDF from 'jspdf';

// ESC/POS commands for thermal printers (as bytes)
const ESC = 0x1B;
const GS = 0x1D;
const LF = 0x0A;

// Command arrays
const INIT = [ESC, 0x40]; // Initialize printer
const CENTER = [ESC, 0x61, 0x01];
const LEFT = [ESC, 0x61, 0x00];
const RIGHT = [ESC, 0x61, 0x02];
const BOLD_ON = [ESC, 0x45, 0x01];
const BOLD_OFF = [ESC, 0x45, 0x00];
const DOUBLE_HEIGHT = [ESC, 0x21, 0x10];
const DOUBLE_WIDTH = [ESC, 0x21, 0x20];
const DOUBLE_SIZE = [ESC, 0x21, 0x30];
const NORMAL_SIZE = [ESC, 0x21, 0x00];
const CUT = [GS, 0x56, 0x00];
const FEED_3 = [ESC, 0x64, 0x03];

export interface PrintOrderData {
  orderNumber: number | string;
  orderType: 'delivery' | 'table' | 'pickup';
  tableName?: string;
  waiterName?: string;
  customerName?: string;
  customerPhone?: string;
  customerCount?: number;
  address?: {
    street: string;
    number: string;
    neighborhood: string;
    complement?: string;
    reference?: string;
  };
  items: Array<{
    name: string;
    quantity: number;
    unitPrice: number;
    observation?: string;
  }>;
  subtotal: number;
  deliveryFee?: number;
  discount?: number;
  serviceFee?: number;
  total: number;
  paymentMethod?: string;
  changeFor?: number;
  createdAt: Date;
  storeName?: string;
}

function formatCurrency(value: number): string {
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);
}

function padRight(str: string, length: number): string {
  return str.substring(0, length).padEnd(length, ' ');
}

function padLeft(str: string, length: number): string {
  return str.substring(0, length).padStart(length, ' ');
}

function formatLine(left: string, right: string, width: number = 32): string {
  const rightLen = right.length;
  const leftLen = width - rightLen - 1;
  return padRight(left, leftLen) + ' ' + right;
}

function dashedLine(width: number = 32): string {
  return '-'.repeat(width);
}

// Wrap text to fit within a specific width
function wrapText(text: string, width: number, indent: string = ''): string[] {
  const words = text.split(' ');
  const lines: string[] = [];
  let currentLine = '';

  words.forEach(word => {
    const testLine = currentLine ? `${currentLine} ${word}` : word;
    if (testLine.length <= width) {
      currentLine = testLine;
    } else {
      if (currentLine) lines.push(indent + currentLine);
      currentLine = word;
    }
  });

  if (currentLine) lines.push(indent + currentLine);
  return lines;
}

// Convert string to bytes using CP437/CP850 compatible encoding
function textToBytes(text: string): number[] {
  const bytes: number[] = [];
  for (let i = 0; i < text.length; i++) {
    const char = text.charAt(i);
    const code = text.charCodeAt(i);

    // Map common Portuguese characters to CP850/CP437 codes
    const charMap: Record<string, number> = {
      'á': 0xA0, 'à': 0x85, 'â': 0x83, 'ã': 0xC6,
      'é': 0x82, 'è': 0x8A, 'ê': 0x88,
      'í': 0xA1, 'ì': 0x8D, 'î': 0x8C,
      'ó': 0xA2, 'ò': 0x95, 'ô': 0x93, 'õ': 0xC7,
      'ú': 0xA3, 'ù': 0x97, 'û': 0x96,
      'ç': 0x87, 'Ç': 0x80,
      'Á': 0xB5, 'À': 0xB7, 'Â': 0xB6, 'Ã': 0xC7,
      'É': 0x90, 'È': 0xD4, 'Ê': 0xD2,
      'Í': 0xD6, 'Ì': 0xDE, 'Î': 0xD7,
      'Ó': 0xE0, 'Ò': 0xE3, 'Ô': 0xE2, 'Õ': 0xE4,
      'Ú': 0xE9, 'Ù': 0xEB, 'Û': 0xEA,
      'ñ': 0xA4, 'Ñ': 0xA5,
      '°': 0xF8,
      '²': 0xFD,
      '³': 0xFC,
    };

    if (charMap[char]) {
      bytes.push(charMap[char]);
    } else if (code < 128) {
      bytes.push(code);
    } else {
      // Fallback for unknown characters
      bytes.push(0x3F); // '?'
    }
  }
  return bytes;
}

function addLine(bytes: number[], text: string): void {
  bytes.push(...textToBytes(text), LF);
}

export function generateReceiptBytes(data: PrintOrderData): Uint8Array {
  const width = 32;
  const bytes: number[] = [];

  // Initialize printer
  bytes.push(...INIT);

  // Set code page to CP850 (Western European)
  bytes.push(ESC, 0x74, 0x02);

  // Header
  bytes.push(...CENTER);
  bytes.push(...DOUBLE_SIZE);
  const isPDVOrder = data.customerName?.startsWith('Comanda #');
  const typeLabel = data.orderType === 'delivery' ? (isPDVOrder ? 'Consumo no local' : 'DELIVERY') : 'COMANDA';
  addLine(bytes, typeLabel);
  bytes.push(...NORMAL_SIZE);
  addLine(bytes, `#${data.orderNumber}`);
  bytes.push(LF);

  // Order info
  bytes.push(...LEFT);
  if (data.orderType === 'table' && data.tableName) {
    bytes.push(...BOLD_ON);
    addLine(bytes, data.tableName);
    bytes.push(...BOLD_OFF);
    if (data.waiterName) {
      addLine(bytes, `Garcom: ${data.waiterName}`);
    }
  } else if (data.orderType === 'delivery') {
    const isPDVOrder = data.customerName?.startsWith('Comanda #');
    bytes.push(...BOLD_ON);
    addLine(bytes, data.customerName || '');
    bytes.push(...BOLD_OFF);

    if (!isPDVOrder) {
      if (data.customerPhone) {
        addLine(bytes, `Tel: ${data.customerPhone}`);
      }
      if (data.address) {
        addLine(bytes, `${data.address.street}, ${data.address.number}`);
        addLine(bytes, data.address.neighborhood);
        if (data.address.complement) {
          // Wrap complement text to fit within printer width
          const complementLines = wrapText(data.address.complement, width - 2, '  ');
          complementLines.forEach(line => addLine(bytes, line));
        }
      }
    }
  }

  // Date/time
  const dateStr = data.createdAt.toLocaleDateString('pt-BR');
  const timeStr = data.createdAt.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  addLine(bytes, `Data: ${dateStr} ${timeStr}`);
  addLine(bytes, dashedLine(width));

  // Items header
  bytes.push(...BOLD_ON);
  addLine(bytes, formatLine('ITEM', 'TOTAL', width));
  bytes.push(...BOLD_OFF);
  addLine(bytes, dashedLine(width));

  // Items
  data.items.forEach(item => {
    const itemTotal = formatCurrency(item.quantity * item.unitPrice);
    addLine(bytes, `${item.quantity}x ${item.name}`);
    bytes.push(...RIGHT);
    addLine(bytes, itemTotal);
    bytes.push(...LEFT);
    if (item.observation) {
      addLine(bytes, `  Obs: ${item.observation}`);
    }
  });

  addLine(bytes, dashedLine(width));

  // Totals
  addLine(bytes, formatLine('Subtotal:', formatCurrency(data.subtotal), width));

  if (data.deliveryFee && data.deliveryFee > 0) {
    addLine(bytes, formatLine('Taxa de entrega:', formatCurrency(data.deliveryFee), width));
  }

  if (data.serviceFee && data.serviceFee > 0) {
    addLine(bytes, formatLine('Taxa de servico:', formatCurrency(data.serviceFee), width));
  }

  if (data.discount && data.discount > 0) {
    addLine(bytes, formatLine('Desconto:', `-${formatCurrency(data.discount)}`, width));
  }

  addLine(bytes, dashedLine(width));
  bytes.push(...BOLD_ON);
  bytes.push(...DOUBLE_HEIGHT);
  addLine(bytes, formatLine('TOTAL:', formatCurrency(data.total), width));
  bytes.push(...NORMAL_SIZE);
  bytes.push(...BOLD_OFF);

  if (data.paymentMethod) {
    bytes.push(LF);
    addLine(bytes, `Pagamento: ${data.paymentMethod}`);
    if (data.changeFor && data.changeFor > 0) {
      addLine(bytes, `Troco para: ${formatCurrency(data.changeFor)}`);
    }
  }

  // Footer
  bytes.push(LF);
  bytes.push(...CENTER);
  addLine(bytes, 'Obrigado pela preferencia!');
  bytes.push(...FEED_3);

  // Cut paper
  bytes.push(...CUT);

  return new Uint8Array(bytes);
}

// Legacy text version for compatibility
export function generateReceiptText(data: PrintOrderData): string {
  const width = 32;
  let receipt = '';

  // ESC/POS as text (legacy)
  const ESC_T = '\x1B';
  const GS_T = '\x1D';

  const isPDVOrder = data.customerName?.startsWith('Comanda #');
  const typeLabel = data.orderType === 'delivery' ? (isPDVOrder ? 'Consumidor Local' : 'DELIVERY') : 'COMANDA';

  receipt += ESC_T + '@'; // Init
  receipt += ESC_T + 'a\x01'; // Center
  receipt += ESC_T + '!\x30'; // Double size
  receipt += typeLabel + '\n';
  receipt += ESC_T + '!\x00'; // Normal
  receipt += `#${data.orderNumber}\n\n`;

  receipt += ESC_T + 'a\x00'; // Left
  if (data.orderType === 'table' && data.tableName) {
    receipt += ESC_T + 'E\x01'; // Bold
    receipt += `${data.tableName}\n`;
    receipt += ESC_T + 'E\x00';
    if (data.waiterName) {
      receipt += `Garcom: ${data.waiterName}\n`;
    }
  } else if (data.orderType === 'delivery') {
    const isPDVOrder = data.customerName?.startsWith('Comanda #');
    receipt += ESC_T + 'E\x01';
    receipt += `${data.customerName}\n`;
    receipt += ESC_T + 'E\x00';

    if (!isPDVOrder) {
      if (data.customerPhone) {
        receipt += `Tel: ${data.customerPhone}\n`;
      }
      if (data.address) {
        receipt += `${data.address.street}, ${data.address.number}\n`;
        receipt += `${data.address.neighborhood}\n`;
        if (data.address.complement) {
          receipt += `${data.address.complement}\n`;
        }
      }
    }
  }

  const dateStr = data.createdAt.toLocaleDateString('pt-BR');
  const timeStr = data.createdAt.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  receipt += `Data: ${dateStr} ${timeStr}\n`;
  receipt += dashedLine(width) + '\n';

  receipt += ESC_T + 'E\x01';
  receipt += formatLine('ITEM', 'TOTAL', width) + '\n';
  receipt += ESC_T + 'E\x00';
  receipt += dashedLine(width) + '\n';

  data.items.forEach(item => {
    const itemTotal = formatCurrency(item.quantity * item.unitPrice);
    receipt += `${item.quantity}x ${item.name}\n`;
    receipt += ESC_T + 'a\x02';
    receipt += `${itemTotal}\n`;
    receipt += ESC_T + 'a\x00';
    if (item.observation) {
      receipt += `  Obs: ${item.observation}\n`;
    }
  });

  receipt += dashedLine(width) + '\n';
  receipt += formatLine('Subtotal:', formatCurrency(data.subtotal), width) + '\n';

  if (data.deliveryFee && data.deliveryFee > 0) {
    receipt += formatLine('Taxa de entrega:', formatCurrency(data.deliveryFee), width) + '\n';
  }
  if (data.serviceFee && data.serviceFee > 0) {
    receipt += formatLine('Taxa de servico:', formatCurrency(data.serviceFee), width) + '\n';
  }
  if (data.discount && data.discount > 0) {
    receipt += formatLine('Desconto:', `-${formatCurrency(data.discount)}`, width) + '\n';
  }

  receipt += dashedLine(width) + '\n';
  receipt += ESC_T + 'E\x01' + ESC_T + '!\x10';
  receipt += formatLine('TOTAL:', formatCurrency(data.total), width) + '\n';
  receipt += ESC_T + '!\x00' + ESC_T + 'E\x00';

  if (data.paymentMethod) {
    receipt += `\nPagamento: ${data.paymentMethod}\n`;
  }

  receipt += '\n' + ESC_T + 'a\x01';
  receipt += 'Obrigado pela preferencia!\n\n\n';
  receipt += GS_T + 'V\x00';

  return receipt;
}

export async function printReceipt(data: PrintOrderData): Promise<boolean> {
  try {
    // Check if Web Serial API is supported
    if (!('serial' in navigator)) {
      throw new Error('Web Serial API não suportada neste navegador. Use Chrome ou Edge.');
    }

    // Request port access
    const port = await (navigator as any).serial.requestPort();

    // Open the port with common thermal printer settings
    await port.open({ 
      baudRate: 9600,
      dataBits: 8,
      stopBits: 1,
      parity: 'none',
      flowControl: 'none'
    });

    const writer = port.writable.getWriter();

    // Generate receipt as raw bytes
    const receiptBytes = generateReceiptBytes(data);

    // Send bytes directly (not encoded text)
    await writer.write(receiptBytes);

    writer.releaseLock();
    await port.close();

    return true;
  } catch (error) {
    console.error('Erro ao imprimir:', error);
    throw error;
  }
}

